  } catch (error) {
    console.error('❌ Resume processing error:', error);
    
    // Send a proper error response
    res.status(500).json({
      success: false,
      message: 'Failed to process resume',
      error: error.message,
      details: process.env.NODE_ENV === 'development' ? error.stack : undefined
    });
