export async function initializeJobScheduler() {
  if (schedulerStarted) {
    console.log('⏰ Job scheduler already running');
    return;
  }

  // Run every day at 9:00 AM
  // Format: "0 9 * * *" = at 09:00 every day
  // For testing every minute: "* * * * *"
  const scheduleTime = process.env.JOB_DIGEST_SCHEDULE || '0 9 * * *';

  console.log(`⏰ Starting job digest scheduler (runs at: ${scheduleTime})`);

  cron.schedule(scheduleTime, async () => {
    console.log('\n📧 Running daily job digest task...');
    await sendDailyJobDigests();
  });

  schedulerStarted = true;
  console.log('✅ Job scheduler initialized successfully');
}

/**
 * Send daily job digests to all registered users
 */
async function sendDailyJobDigests() {
  try {
    const users = await User.find({ email: { $ne: null } }).lean();
    console.log(`👥 Found ${users.length} users to send job digests to`);

    let successCount = 0;
    let failureCount = 0;

    for (const user of users) {
      try {
        // Fetch jobs posted in the last 24 hours
        const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
        const recentJobs = await JobListing.find({
          postedDate: { $gte: twentyFourHoursAgo }
        })
          .sort({ postedDate: -1 })
          .limit(15)
          .lean();

        if (recentJobs.length === 0) {
          console.log(`ℹ️ No new jobs for ${user.email}, skipping`);
          continue;
        }

        // Send email with recent jobs
        const result = await sendJobDigestEmail(
          user.email,
          user.name || user.email.split('@')[0],
          recentJobs
        );

        if (result.success) {
          successCount++;
        } else {
          failureCount++;
        }
      } catch (error) {
        console.error(`❌ Error processing user ${user.email}:`, error.message);
        failureCount++;
      }
    }

    console.log(`✅ Job digest task completed: ${successCount} sent, ${failureCount} failed`);
  } catch (error) {
    console.error('❌ Fatal error in daily job digest task:', error);
  }
}

/**
 * Send job digest to a specific user (manual trigger)
 */
export async function sendJobDigestToUser(userId) {
  try {
    const user = await User.findById(userId);
    if (!user || !user.email) {
      return { success: false, message: 'User not found or has no email' };
    }

    const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
    const recentJobs = await JobListing.find({
      postedDate: { $gte: twentyFourHoursAgo }
    })
      .sort({ postedDate: -1 })
      .limit(15)
      .lean();

    if (recentJobs.length === 0) {
      return { success: false, message: 'No new jobs available' };
    }

    const result = await sendJobDigestEmail(
      user.email,
      user.name || user.email.split('@')[0],
      recentJobs
    );

    return result;
  } catch (error) {
    console.error('❌ Error sending digest to user:', error);
    return { success: false, error: error.message };
  }
}

export default { initializeJobScheduler, sendJobDigestToUser };

import pdfParse from 'pdf-parse';
import Tesseract from 'tesseract.js';
import pdf2json from 'pdf2json';
import fs from 'fs';
import path from 'path';

class PDFProcessor {
  async extractTextFromPDF(buffer) {
    try {
      console.log('📄 Processing PDF buffer...');
      console.log('📊 Buffer size:', buffer.length, 'bytes');

      // Try multiple extraction methods
      let extractedText = '';

      // Method 1: pdf-parse
      try {
        const data = await pdfParse(buffer);
        extractedText = data.text.trim();
        console.log('✅ pdf-parse extracted text length:', extractedText.length);

        if (extractedText.length > 50) {
          console.log('📄 First 200 chars:', extractedText.substring(0, 200));
          return this.cleanExtractedText(extractedText);
        }
      } catch (err) {
        console.error('❌ pdf-parse failed:', err);
      }

      // Method 2: pdf2json
      if (!extractedText || extractedText.length < 50) {
        console.log('🔄 Trying pdf2json...');
        try {
          extractedText = await this.extractWithPdf2json(buffer);
          console.log('✅ pdf2json extracted text length:', extractedText.length);

          if (extractedText.length > 50) {
            return this.cleanExtractedText(extractedText);
          }
        } catch (err) {
          console.error('❌ pdf2json failed:', err);
        }
      }

      // Method 3: OCR fallback
      if (!extractedText || extractedText.length < 50) {
        console.log('🔍 No sufficient text found, running OCR fallback...');
        extractedText = await this.extractTextWithOCR(buffer);
        console.log('✅ OCR extracted text length:', extractedText.length);
      }

      return this.cleanExtractedText(extractedText);
    } catch (error) {
      console.error('❌ PDF processing error:', error);
      throw new Error('PDF processing failed: ' + error.message);
    }
  }

  async extractWithPdf2json(buffer) {
    return new Promise((resolve, reject) => {
      const pdfParser = new pdf2json();

      pdfParser.on('pdfParser_dataError', errData => {
        reject(new Error(errData.parserError));
      });

      pdfParser.on('pdfParser_dataReady', pdfData => {
        try {
          let text = '';

          pdfData.Pages.forEach(page => {
            page.Texts.forEach(textItem => {
              textItem.R.forEach(run => {
                if (run.T) {
                  text += decodeURIComponent(run.T) + ' ';
                }
              });
            });
            text += '\n';
          });

          resolve(text.trim());
        } catch (err) {
          reject(err);
        }
      });

      pdfParser.parseBuffer(buffer);
    });
  }

  // Best-effort: try to find an embedded image and persist it to /uploads
  async extractFirstImageToFile(buffer) {
    try {
      const uploadDir = path.join(process.cwd(), 'uploads');
      if (!fs.existsSync(uploadDir)) {
        fs.mkdirSync(uploadDir, { recursive: true });
      }

      const data = await new Promise((resolve, reject) => {
        const parser = new pdf2json();
        parser.on('pdfParser_dataError', err => reject(new Error(err.parserError)));
        parser.on('pdfParser_dataReady', pdfData => resolve(pdfData));
        parser.parseBuffer(buffer);
      });

      const pageArray = Array.isArray(data?.Pages) ? data.Pages : [];
      const candidateKeys = ['Images', 'Image', 'Imgs', 'XObject', 'xObject'];

      for (const page of pageArray) {
        for (const key of candidateKeys) {
          const value = page?.[key];
          if (!value) continue;
          const imageArray = Array.isArray(value) ? value : (Array.isArray(value?.List) ? value.List : []);
          for (const img of imageArray) {
            const dataUri = img?.src || img?.dataURI || img?.DataURI || img?.dataUrl || img?.dataURL;
            if (typeof dataUri === 'string' && dataUri.startsWith('data:image/')) {
              const match = dataUri.match(/^data:(image\/[a-zA-Z]+);base64,(.*)$/);
              if (!match) continue;
              const ext = match[1].split('/')[1].toLowerCase();
              const base64 = match[2];
              const filename = `resume-photo-${Date.now()}.${ext}`;
              const filePath = path.join(uploadDir, filename);
              fs.writeFileSync(filePath, Buffer.from(base64, 'base64'));
              console.log('🖼️ Extracted embedded data-URI image from pdf2json');
              return `/uploads/${filename}`;
            }
          }
        }
      }
      // Fallback: scan PDF buffer for embedded JPEG/PNG/WEBP by magic bytes
      const tryMagic = this.extractEmbeddedImageByMagic(buffer, uploadDir);
      if (tryMagic) return tryMagic;
      return null;
    } catch (err) {
      console.warn('⚠️ No embedded image extracted from PDF:', err.message);
      return null;
    }
  }

  extractEmbeddedImageByMagic(buffer, uploadDir) {
    const candidates = [];
    // JPEG: FF D8 ... FF D9
    for (let i = 0; i < buffer.length - 1; i++) {
      if (buffer[i] === 0xFF && buffer[i + 1] === 0xD8) {
        for (let j = i + 2; j < buffer.length - 1; j++) {
          if (buffer[j] === 0xFF && buffer[j + 1] === 0xD9) {
            const size = j + 2 - i;
            if (size > 2 * 1024 && size < 10 * 1024 * 1024) {
              candidates.push({ start: i, end: j + 2, ext: 'jpg', size });
            }
            i = j + 1;
            break;
          }
        }
      }
    }
    // PNG: 89 50 4E 47 0D 0A 1A 0A ... IEND AE 42 60 82
    const pngSig = Buffer.from([0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A]);
    for (let i = 0; i < buffer.length - pngSig.length; i++) {
      if (buffer.slice(i, i + pngSig.length).equals(pngSig)) {
        // search for IEND trailer
        for (let j = i + pngSig.length; j < buffer.length - 8; j++) {
          if (buffer[j] === 0x49 && buffer[j + 1] === 0x45 && buffer[j + 2] === 0x4E && buffer[j + 3] === 0x44 &&
            buffer[j + 4] === 0xAE && buffer[j + 5] === 0x42 && buffer[j + 6] === 0x60 && buffer[j + 7] === 0x82) {
            const size = j + 8 - i;
            if (size > 2 * 1024 && size < 10 * 1024 * 1024) {
              candidates.push({ start: i, end: j + 8, ext: 'png', size });
            }
            i = j + 7;
            break;
          }
        }
      }
    }
    // WEBP: RIFF xxxx WEBP
    const riff = Buffer.from('RIFF');
    const webp = Buffer.from('WEBP');
    for (let i = 0; i < buffer.length - 12; i++) {
      if (buffer.slice(i, i + 4).equals(riff) && buffer.slice(i + 8, i + 12).equals(webp)) {
        const sizeLE = buffer.readUInt32LE(i + 4); // size of RIFF chunk excluding 8 bytes
        const total = sizeLE + 8;
        const end = i + total;
        if (end <= buffer.length && total > 2 * 1024 && total < 10 * 1024 * 1024) {
          candidates.push({ start: i, end, ext: 'webp', size: total });
          i = end - 1;
        }
      }
    }

    if (candidates.length === 0) return null;
    // pick the largest sensible candidate (likely the headshot)
    candidates.sort((a, b) => b.size - a.size);
    const best = candidates[0];
    const filename = `resume-photo-${Date.now()}.${best.ext}`;
    fs.writeFileSync(path.join(uploadDir, filename), buffer.slice(best.start, best.end));
    console.log(`🖼️ Extracted embedded image by magic bytes: ${best.ext}, ${Math.round(best.size / 1024)}KB`);
    return `/uploads/${filename}`;
  }

  cleanExtractedText(text) {
    return text
      .replace(/\s+/g, ' ') // Replace multiple spaces with single space
      .replace(/\n\s*\n/g, '\n') // Remove empty lines
      .replace(/([a-z])([A-Z])/g, '$1 $2') // Add space between camelCase
      .replace(/([0-9])([A-Z])/g, '$1 $2') // Add space between number and letter
      .trim();
  }

  async extractTextWithOCR(buffer) {
    try {
      // Convert buffer to base64 for tesseract.js
      const base64 = buffer.toString('base64');
      const image = `data:application/pdf;base64,${base64}`;

      const { data: { text } } = await Tesseract.recognize(image, 'eng', {
        logger: m => console.log('🔍 OCR:', m.status, m.progress),
        tessedit_char_whitelist: 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789 .,-:@()[]{}|+-=_/\\#'
      });

      return text.trim();
    } catch (err) {
      console.error('❌ OCR extraction failed:', err);
      return '';
    }
  }
}

const pdfProcessor = new PDFProcessor();
export default pdfProcessor;

// Utility to refine and normalize AI-extracted resume data
// - Deduplicate/limit skills
// - Normalize social usernames
// - Strengthen summary if weak
// - Expand/clean work experience descriptions
// - Ensure education fields are consistent

function sanitizeUsernameFromUrl(value) {
	if (!value || typeof value !== 'string') return '';
	const v = value.trim();
	try {
		// If it's already a simple username (no spaces, no slashes), return cleaned
		if (!v.includes('http') && !v.includes('/')) {
			return v.replace(/^@/, '').replace(/\s+/g, '').trim();
		}
		// Extract last non-empty path segment
		const url = new URL(v.startsWith('http') ? v : `https://${v.replace(/^\/*/, '')}`);
		const parts = url.pathname.split('/').filter(Boolean);
		if (parts.length === 0) return '';
		return parts[parts.length - 1].replace(/^@/, '').replace(/\s+/g, '').trim();
	} catch (_) {
		// Fallback: strip protocol and take last segment
		const parts = v.replace(/^https?:\/\//, '').split('/').filter(Boolean);
		if (parts.length === 0) return '';
		return parts[parts.length - 1].replace(/^@/, '').replace(/\s+/g, '').trim();
	}
}

function dedupeAndLimitSkills(skills, limit = 10) {
	if (!Array.isArray(skills)) return [];
	const seen = new Set();
	const cleaned = [];
	for (const s of skills) {
		if (!s) continue;
		const skill = String(s).trim().replace(/\s+/g, ' ');
		const key = skill.toLowerCase();
		if (skill.length < 2) continue;
		if (!seen.has(key)) {
			seen.add(key);
			cleaned.push(skill);
		}
		if (cleaned.length >= limit) break;
	}
	return cleaned;
}

function strengthenSummary(summary, header) {
	const base = (summary || '').trim();
	if (base.length >= 180) return base; // already decent
	const name = header?.name || 'The candidate';
	const role = header?.shortAbout || '';
	const skillsLine = (header?.skills || []).slice(0, 4).join(', ');
	const pieces = [
		`${name} is a highly accomplished professional${role ? ` — ${role}` : ''}.`,
		skillsLine ? `Core strengths include ${skillsLine}.` : '',
		'Experienced in delivering measurable outcomes and collaborating across teams.'
	].filter(Boolean);
	return pieces.join(' ');
}

function normalizeContacts(contacts = {}) {
	const normalized = { ...contacts };
	if (normalized.linkedin) normalized.linkedin = sanitizeUsernameFromUrl(normalized.linkedin);
	if (normalized.twitter) normalized.twitter = sanitizeUsernameFromUrl(normalized.twitter);
	if (normalized.github) normalized.github = sanitizeUsernameFromUrl(normalized.github);
	// Keep phone/email/website as-is (trim)
	['email', 'phone', 'website'].forEach(k => {
		if (normalized[k]) normalized[k] = String(normalized[k]).trim();
	});
	return normalized;
}

function cleanDescription(text) {
	if (!text) return '';
	// Normalize bullet separators
	let t = String(text).replace(/\u2022|•|\-|–/g, '\n').replace(/\r/g, '');
	// Collapse multiple newlines
	t = t.split(/\n+/).map(s => s.trim()).filter(Boolean).join('\n');
	// Keep it within a reasonable length
	if (t.length > 1200) t = t.slice(0, 1200);
	return t;
}

function refineWorkExperience(items = []) {
	if (!Array.isArray(items)) return [];
	return items.map((item, idx) => {
		const refined = { ...item };
		refined.company = (refined.company || '').trim();
		refined.title = (refined.title || '').trim();
		refined.location = (refined.location || '').trim();
		refined.contract = (refined.contract || '').trim();
		refined.description = cleanDescription(refined.description || '');
		return refined;
	});
}

function refineEducation(items = []) {
	if (!Array.isArray(items)) return [];
	return items.map(e => ({
		school: (e.school || '').trim(),
		degree: (e.degree || '').trim(),
		start: (e.start || '').trim(),
		end: (e.end || '').trim()
	}));
}

export function refineResumeData(resumeData = {}) {
	const data = { ...resumeData };
	data.header = data.header || {};
	data.header.name = (data.header.name || '').trim();
	data.header.shortAbout = (data.header.shortAbout || '').trim();
	data.header.location = (data.header.location || '').trim();
	data.header.contacts = normalizeContacts(data.header.contacts || {});
	data.header.skills = dedupeAndLimitSkills(data.header.skills || [], 10);

	data.summary = strengthenSummary(data.summary || '', data.header);
	data.workExperience = refineWorkExperience(data.workExperience || []);
	data.education = refineEducation(data.education || []);
	return data;
}

// Simple fallback contact extraction from raw text (regex-based)
export function extractFallbackContacts(rawText = '') {
	if (!rawText) return {};
	const email = (rawText.match(/[\w.+-]+@[\w-]+\.[\w.-]+/i) || [])[0] || '';
	const phone = (rawText.match(/\+?\d[\d\s().-]{7,}/) || [])[0] || '';
	const linkedin = sanitizeUsernameFromUrl((rawText.match(/linkedin\.com\/[A-Za-z0-9_\-/]+/i) || [])[0] || '');
	const github = sanitizeUsernameFromUrl((rawText.match(/github\.com\/[A-Za-z0-9_\-/]+/i) || [])[0] || '');
	const twitter = sanitizeUsernameFromUrl((rawText.match(/(?:x\.com|twitter\.com)\/[A-Za-z0-9_\-/]+/i) || [])[0] || '');
	return { email, phone, linkedin, github, twitter };
}

