                  ...prev,
                  certifications: [...(prev.certifications || []), newCertification]
                }));
              }}
              className="bg-orange-600 hover:bg-orange-700 text-white px-6 py-3 rounded-lg font-medium transition-colors duration-200 flex items-center gap-2"
