              + Add Certification
            </button>
          </div>
        </div>
      )}

      {/* Action Buttons */}
      <div className={`flex justify-center gap-4 mt-8 pt-6 border-t ${themeColors.border[colorMode]}`}>
        {isEditing ? (
          <>
            <button
              onClick={handleSave}
              className="bg-green-600 hover:bg-green-700 text-white px-8 py-3 rounded-lg font-medium transition-colors duration-200 flex items-center gap-2"
            >
              <FaSave /> Save Changes
            </button>
            <button
              onClick={handleCancel}
              className="bg-gray-600 hover:bg-gray-700 text-white px-8 py-3 rounded-lg font-medium transition-colors duration-200 flex items-center gap-2"
            >
              <FaTimes /> Cancel
            </button>
          </>
        ) : (
          <>
            <button
              onClick={handleEdit}
              className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-lg font-medium transition-colors duration-200 flex items-center gap-2"
            >
              <FaEdit /> Edit Portfolio
            </button>
          </>
        )}
      </div>
    </>
  );
};

export default EditButtons;

import React from "react";
import { getThemeColors } from "../utils/themes";

const Education = ({ displayData, isEditing, editData, handleArrayChange, currentTheme, theme: colorMode }) => {
  const themeColors = getThemeColors(currentTheme, colorMode);
  const accentColor = colorMode === 'light' ? themeColors.accent : themeColors.accentDark;

  return (
    <section className="mb-10">
      <h2 className={`text-${accentColor} text-2xl md:text-3xl mb-6 relative pb-2 after:content-[''] after:absolute after:bottom-0 after:left-0 after:w-12 after:h-1 after:bg-${accentColor}`}>
        Education
      </h2>
      <div className="space-y-4">
        {displayData.education?.map((edu, index) => (
          <div key={index} className={`${themeColors.cardHover[colorMode]} p-6 rounded-xl transition-all duration-300 hover:-translate-y-1 hover:shadow-lg`}>
            {isEditing ? (
              <div className="space-y-3">
                <input
                  type="text"
                  value={edu.degree || ''}
                  onChange={(e) => handleArrayChange('education', index, {...edu, degree: e.target.value})}
                  className={`w-full text-lg font-semibold ${themeColors.text.primary[colorMode]} bg-transparent border-b ${themeColors.input[colorMode]} focus:outline-none focus:border-${accentColor}`}
                  placeholder="Degree/Qualification"
                />
                <input
                  type="text"
                  value={edu.institution || ''}
                  onChange={(e) => handleArrayChange('education', index, {...edu, institution: e.target.value})}
                  className={`w-full text-base font-medium text-${accentColor} bg-transparent border-b ${themeColors.input[colorMode]} focus:outline-none focus:border-${accentColor}`}
                  placeholder="Institution"
                />
                <div className="flex gap-4">
                  <input
                    type="text"
                    value={edu.duration || ''}
                    onChange={(e) => handleArrayChange('education', index, {...edu, duration: e.target.value})}
                    className={`flex-1 text-sm ${themeColors.text.secondary[colorMode]} bg-transparent border-b ${themeColors.input[colorMode]} focus:outline-none focus:border-${accentColor}`}
                    placeholder="Duration"
                  />
                  <input
                    type="text"
                    value={edu.grade || ''}
                    onChange={(e) => handleArrayChange('education', index, {...edu, grade: e.target.value})}
                    className={`flex-1 text-sm ${themeColors.text.secondary[colorMode]} bg-transparent border-b ${themeColors.input[colorMode]} focus:outline-none focus:border-${accentColor}`}
                    placeholder="Grade/Score"
                  />
                </div>
              </div>
            ) : (
              <>
                <h3 className={`text-lg font-semibold mb-2 ${themeColors.text.primary[colorMode]}`}>
                  {edu.degree}
                </h3>
                {edu.institution && (
                  <h4 className={`text-base font-medium text-${accentColor} mb-2`}>
                    {edu.institution}
                  </h4>
                )}
                <p className={`text-sm ${themeColors.text.secondary[colorMode]}`}>
                  {edu.duration && edu.grade ? `${edu.duration} | ${edu.grade}` : edu.duration || edu.grade}
                </p>
              </>
            )}
          </div>
        ))}
      </div>
    </section>
  );
};

export default Education;

import React from "react";
import { getThemeColors } from "../utils/themes";

const Experience = ({ displayData, isEditing, editData, handleArrayChange, currentTheme, theme: colorMode }) => {
  if (!displayData.experience || displayData.experience.length === 0) {
    return null;
  }

  const themeColors = getThemeColors(currentTheme, colorMode);
  const accentColor = colorMode === 'light' ? themeColors.accent : themeColors.accentDark;

  return (
    <section className="mb-10">
      <h2 className={`text-${accentColor} text-2xl md:text-3xl mb-6 relative pb-2 after:content-[''] after:absolute after:bottom-0 after:left-0 after:w-12 after:h-1 after:bg-${accentColor}`}>
        Experience
      </h2>
      <div className="space-y-4">
        {displayData.experience.map((exp, index) => (
          <div key={index} className={`${themeColors.cardHover[colorMode]} p-6 rounded-xl transition-all duration-300 hover:-translate-y-1 hover:shadow-lg`}>
            {isEditing ? (
              <div className="space-y-3">
                <input
                  type="text"
                  value={exp.title || ''}
                  onChange={(e) => handleArrayChange('experience', index, {...exp, title: e.target.value})}
                  className={`w-full text-lg font-semibold ${themeColors.text.primary[colorMode]} bg-transparent border-b ${themeColors.input[colorMode]} focus:outline-none focus:border-${accentColor}`}
                  placeholder="Job Title"
                />
                <input
                  type="text"
                  value={exp.company || ''}
                  onChange={(e) => handleArrayChange('experience', index, {...exp, company: e.target.value})}
                  className={`w-full text-base font-medium text-${accentColor} bg-transparent border-b ${themeColors.input[colorMode]} focus:outline-none focus:border-${accentColor}`}
                  placeholder="Company Name"
                />
                <input
                  type="text"
                  value={exp.duration || ''}
                  onChange={(e) => handleArrayChange('experience', index, {...exp, duration: e.target.value})}
                  className={`w-full text-sm ${themeColors.text.secondary[colorMode]} bg-transparent border-b ${themeColors.input[colorMode]} focus:outline-none focus:border-${accentColor}`}
                  placeholder="Duration"
                />
                <textarea
                  value={exp.description || ''}
                  onChange={(e) => handleArrayChange('experience', index, {...exp, description: e.target.value})}
                  className={`w-full text-sm ${themeColors.text.secondary[colorMode]} bg-transparent border ${themeColors.input[colorMode]} rounded p-2 focus:outline-none focus:border-${accentColor} resize-none`}
                  placeholder="Job Description"
                  rows="3"
                />
              </div>
            ) : (
              <>
                <h3 className={`text-lg font-semibold mb-2 ${themeColors.text.primary[colorMode]}`}>
                  {exp.title}
                </h3>
                <h4 className={`text-base font-medium text-${accentColor} mb-2`}>
                  {exp.company}
                </h4>
                <p className={`text-sm ${themeColors.text.secondary[colorMode]} mb-2`}>
                  {exp.duration}
                </p>
                {exp.description && (
                  <p className={`text-sm ${themeColors.text.secondary[colorMode]}`}>
                    {exp.description}
                  </p>
                )}
              </>
            )}
          </div>
        ))}
      </div>
    </section>
  );
};

export default Experience;

import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { FaBriefcase, FaMapMarkerAlt, FaBuilding, FaClock, FaExternalLinkAlt, FaChevronLeft, FaChevronRight, FaAngleDoubleLeft, FaAngleDoubleRight, FaFilter, FaStar, FaUserGraduate, FaUserTie, FaSyncAlt, FaSortAmountDown, FaSearch, FaTimes, FaArrowRight } from 'react-icons/fa';

const JobRecommendations = ({ userId, sessionId, apiBaseUrl = 'http://localhost:5000' }) => {
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [stats, setStats] = useState(null);
  const [selectedJob, setSelectedJob] = useState(null);
  const [initialLoad, setInitialLoad] = useState(true);

  // Portfolio state
  const [portfolios, setPortfolios] = useState([]);
  const [selectedPortfolioId, setSelectedPortfolioId] = useState('');
  const [loadingPortfolios, setLoadingPortfolios] = useState(false);

  // Pagination state
  const [pagination, setPagination] = useState({
    currentPage: 1,
    perPage: 10,
    totalJobs: 0,
    totalPages: 0,
    hasNextPage: false,
    hasPrevPage: false
  });

  // Filter state
  const [filters, setFilters] = useState({
    experienceLevel: '', // '' | 'fresher' | 'experienced' — mandatory
    location: '',
    jobType: 'all',
    source: 'all',
    sortBy: 'score',
    perPage: 10
  });

  // Track if experience level has been selected (mandatory)
  const [experienceSelected, setExperienceSelected] = useState(false);

  // Fetch job stats
  const fetchStats = useCallback(async () => {
    try {
      const response = await axios.get(`${apiBaseUrl}/api/jobs/stats`);
      if (response.data.success) {
        setStats(response.data.statistics);
      }
    } catch (err) {
      console.error('Error fetching stats:', err);
    }
  }, [apiBaseUrl]);

  // Fetch Portfolios
  const fetchPortfolios = useCallback(async () => {
    if (!sessionId && !userId) return;
    try {
      setLoadingPortfolios(true);
      // Fallback to sessionId to fetch user's portfolios
      const sid = sessionId || 'default'; // In this app typically sessionId is used if userId isn't directly passed for auth
      const response = await axios.get(`${apiBaseUrl}/api/user/${sid}/portfolios`);
      if (response.data.success) {
        setPortfolios(response.data.portfolios || []);
      }
    } catch (err) {
      console.error('Error fetching portfolios:', err);
    } finally {
      setLoadingPortfolios(false);
    }
  }, [apiBaseUrl, sessionId, userId]);

  // Fetch recommendations with pagination
  const fetchRecommendations = useCallback(async (page = 1) => {
    if (!experienceSelected) return;

    try {
      setLoading(true);
      setError(null);

      const endpoint = userId
        ? `/api/jobs/recommendations/${userId}`
        : `/api/jobs/recommendations/session/${sessionId}`;

      const params = new URLSearchParams({
        page: page.toString(),
        perPage: filters.perPage.toString(),
        sortBy: filters.sortBy,
        experienceLevel: filters.experienceLevel,
        ...(selectedPortfolioId && { portfolioId: selectedPortfolioId }),
        ...(filters.location && { location: filters.location }),
        ...(filters.jobType !== 'all' && { jobType: filters.jobType }),
        ...(filters.source !== 'all' && { source: filters.source })
      });

      const response = await axios.get(`${apiBaseUrl}${endpoint}?${params}`);

      if (response.data.success) {
        setRecommendations(response.data.recommendations);
        setPagination(response.data.pagination);
      } else {
        setError(response.data.message || 'Failed to fetch recommendations');
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Error fetching recommendations');
      console.error('Error:', err);
    } finally {
      setLoading(false);
      setInitialLoad(false);
    }
  }, [userId, sessionId, apiBaseUrl, filters, experienceSelected]);

  // Initial stats fetch
  useEffect(() => {
    if (userId || sessionId) {
      fetchStats();
      fetchPortfolios();
    }
  }, [userId, sessionId, fetchStats, fetchPortfolios]);

  // Fetch when experience level is selected for the first time
  useEffect(() => {
    if (experienceSelected && selectedPortfolioId && (userId || sessionId)) {
      fetchRecommendations(1);
    }
  }, [experienceSelected, selectedPortfolioId]);

  // Handle experience level selection (mandatory)
  const handleExperienceSelect = (level) => {
    setFilters(prev => ({ ...prev, experienceLevel: level }));
    setExperienceSelected(true);
  };

  // Handle filter changes
  const handleFilterChange = (key, value) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  // Apply filters (reset to page 1)
  const handleApplyFilters = () => {
    fetchRecommendations(1);
  };

  // Page navigation
  const goToPage = (page) => {
    if (page >= 1 && page <= pagination.totalPages) {
      fetchRecommendations(page);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // Fetch fresh jobs
  const handleFreshFetch = async () => {
    try {
      setLoading(true);
      await axios.post(`${apiBaseUrl}/api/jobs/fetch-fresh`, {
        userId,
        sessionId,
        portfolioId: selectedPortfolioId
      });
      await fetchStats();
      await fetchRecommendations(1);
    } catch (err) {
      setError('Failed to fetch fresh job listings');
    } finally {
      setLoading(false);
    }
  };

  // Generate page numbers for pagination
  const getPageNumbers = () => {
    const { currentPage, totalPages } = pagination;
    const pages = [];
    const maxVisible = 7;

    if (totalPages <= maxVisible) {
      for (let i = 1; i <= totalPages; i++) pages.push(i);
    } else {
      pages.push(1);
      if (currentPage > 3) pages.push('...');

      const start = Math.max(2, currentPage - 1);
      const end = Math.min(totalPages - 1, currentPage + 1);
      for (let i = start; i <= end; i++) pages.push(i);

      if (currentPage < totalPages - 2) pages.push('...');
      pages.push(totalPages);
    }
    return pages;
  };

  // Match score color
  const getScoreColor = (score) => {
    if (score >= 70) return { bg: 'bg-green-100', text: 'text-green-700', border: 'border-green-300' };
    if (score >= 40) return { bg: 'bg-yellow-100', text: 'text-yellow-700', border: 'border-yellow-300' };
    return { bg: 'bg-red-100', text: 'text-red-700', border: 'border-red-300' };
  };

  // ─── PORTFOLIO SELECTION (STEP 1) ───
  if (loadingPortfolios && !selectedPortfolioId && portfolios.length === 0) {
    return (
      <div className="w-full max-w-6xl mx-auto p-6 flex flex-col items-center justify-center min-h-[50vh]">
        <FaSyncAlt className="animate-spin text-blue-500 text-4xl mb-4" />
        <h2 className="text-xl font-bold text-gray-700">Loading your portfolios...</h2>
      </div>
    );
  }

  if (!selectedPortfolioId) {
    return (
      <div className="w-full max-w-7xl mx-auto p-4 sm:p-6 lg:p-8">
        <div className="bg-white rounded-3xl shadow-xl border border-gray-100 p-8 md:p-12 mb-8">
          <div className="text-center max-w-2xl mx-auto mb-12">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-blue-50 text-blue-500 mb-6 mx-auto">
              <FaBriefcase className="w-10 h-10" />
            </div>
            <h2 className="text-4xl font-extrabold text-gray-900 mb-4 tracking-tight">Select a Portfolio</h2>
            <p className="text-lg text-gray-500">
              Choose the portfolio profile you want to use. We will analyze its skills and experience to find the perfect jobs for you.
            </p>
          </div>

          {portfolios.length === 0 ? (
            <div className="py-16 text-center bg-gray-50 rounded-2xl border-2 border-dashed border-gray-300">
              <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
                <FaBriefcase className="text-4xl text-gray-300" />
              </div>
              <p className="text-xl font-medium text-gray-900 mb-2">You haven't generated any portfolios yet!</p>
              <p className="text-gray-500 mb-8 max-w-md mx-auto">Create a portfolio first to get AI-matched job recommendations tailored to your skills.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {portfolios.map(portfolio => (
                <button
                  key={portfolio._id}
                  onClick={() => setSelectedPortfolioId(portfolio._id)}
                  className="group relative bg-white rounded-2xl border-2 border-gray-200 hover:border-blue-500 hover:shadow-2xl hover:-translate-y-1 transition-all duration-300 text-left overflow-hidden flex flex-col h-full"
                >
                  {/* Portfolio Header matching Dashboard */}
                  <div className="p-6 border-b border-gray-100 bg-gradient-to-br from-gray-50 to-white flex-1">
                    <div className="flex items-start gap-4 mb-4">
                      <div className="w-16 h-16 rounded-xl overflow-hidden bg-white shadow-sm border border-gray-100 flex-shrink-0 flex items-center justify-center group-hover:shadow-md transition-shadow">
                        {portfolio.header?.photoUrl ? (
                          <img src={`${apiBaseUrl}${portfolio.header.photoUrl}`} alt="Profile" className="w-full h-full object-cover" />
                        ) : (
                          <span className="text-gray-400 font-bold text-2xl">{portfolio.header?.name?.charAt(0) || portfolio.title?.charAt(0) || 'P'}</span>
                        )}
                      </div>
                      <div>
                        <h3 className="text-xl font-bold text-gray-900 line-clamp-1 group-hover:text-blue-600 transition-colors">
                          {portfolio.header?.name || portfolio.title}
                        </h3>
                        <p className="text-sm font-medium text-blue-600 mt-1">
                          {portfolio.personaType || 'Professional Profile'}
                        </p>
                      </div>
                    </div>
                    <p className="text-gray-600 text-sm line-clamp-3 mb-4">
                      {portfolio.header?.shortAbout || portfolio.summary || 'A professional portfolio ready to be matched with opportunities.'}
                    </p>
                  </div>

                  {/* Portfolio Stats below */}
                  <div className="p-6 bg-white border-t border-gray-50">
                    <div className="flex items-center justify-between gap-4 mb-6">
                      <div className="flex-1 p-3 rounded-xl bg-blue-50/50 border border-blue-100">
                        <div className="text-2xl font-bold text-blue-700">{portfolio.header?.skills?.length || 0}</div>
                        <div className="text-xs font-medium text-blue-600 uppercase tracking-wider mt-1">Skills</div>
                      </div>
                      <div className="flex-1 p-3 rounded-xl bg-green-50/50 border border-green-100">
                        <div className="text-2xl font-bold text-green-700">{portfolio.workExperience?.length || 0}</div>
                        <div className="text-xs font-medium text-green-600 uppercase tracking-wider mt-1">Positions</div>
                      </div>
                    </div>
                    <div className="w-full py-3 px-4 rounded-xl bg-gray-900 text-white font-medium text-center group-hover:bg-blue-600 transition-colors flex items-center justify-center gap-2">
                      <span>Select Portfolio</span>
                      <FaArrowRight className="text-sm group-hover:translate-x-1 transition-transform" />
                    </div>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  }

  // ─── EXPERIENCE LEVEL SELECTION (STEP 2) ───
  if (!experienceSelected) {
    return (
      <div className="w-full max-w-6xl mx-auto p-6">
        {/* Stats */}
        {stats && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
            <div className="bg-gradient-to-br from-green-50 to-green-100 p-4 rounded-xl border border-green-200">
              <div className="text-sm text-gray-500 mb-1">Status</div>
              <div className="text-3xl font-bold text-green-700">Ready to Match</div>
            </div>
          </div>
        )}

        {/* Mandatory Experience Selection */}
        <div className="bg-white rounded-2xl shadow-lg border border-gray-200 p-8 text-center max-w-2xl mx-auto">
          <div className="text-5xl mb-4">🎯</div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Let's Find Your Perfect Job</h2>
          <p className="text-gray-500 mb-8">Select your experience level to get personalized job recommendations matched to your resume</p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Fresher Card */}
            <button
              onClick={() => handleExperienceSelect('fresher')}
              className="group p-6 rounded-xl border-2 border-gray-200 hover:border-blue-500 hover:shadow-lg transition-all duration-200 text-left bg-gradient-to-br from-blue-50 to-white"
            >
              <div className="flex items-center gap-3 mb-3">
                <div className="w-12 h-12 rounded-full bg-blue-100 flex items-center justify-center group-hover:bg-blue-200 transition">
                  <FaUserGraduate className="text-blue-600 text-xl" />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-gray-900">Fresher</h3>
                  <p className="text-sm text-gray-500">0-1 years experience</p>
                </div>
              </div>
              <p className="text-sm text-gray-600">Entry-level, internships, graduate roles, and junior positions</p>
            </button>

            {/* Experienced Card */}
            <button
              onClick={() => handleExperienceSelect('experienced')}
              className="group p-6 rounded-xl border-2 border-gray-200 hover:border-indigo-500 hover:shadow-lg transition-all duration-200 text-left bg-gradient-to-br from-indigo-50 to-white"
            >
              <div className="flex items-center gap-3 mb-3">
                <div className="w-12 h-12 rounded-full bg-indigo-100 flex items-center justify-center group-hover:bg-indigo-200 transition">
                  <FaUserTie className="text-indigo-600 text-xl" />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-gray-900">Experienced</h3>
                  <p className="text-sm text-gray-500">2+ years experience</p>
                </div>
              </div>
              <p className="text-sm text-gray-600">Mid-level, senior, lead, and management positions</p>
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ─── MAIN JOB RECOMMENDATIONS VIEW ───
  return (
    <div className="w-full max-w-6xl mx-auto p-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between mb-6">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 mb-1">
            🎯 Job Recommendations
          </h1>
          <p className="text-gray-500">
            AI-matched jobs for your resume • {filters.experienceLevel === 'fresher' ? '👨‍🎓 Fresher' : '👔 Experienced'} roles
          </p>
        </div>
        <div className="flex items-center gap-2 mt-3 md:mt-0">
          {portfolios.length > 1 && (
            <button
              onClick={() => { setSelectedPortfolioId(''); setExperienceSelected(false); setRecommendations([]); }}
              className="px-3 py-2 text-sm bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition flex items-center gap-1"
            >
              <FaTimes className="text-xs" /> Change Portfolio
            </button>
          )}
          <button
            onClick={() => { setExperienceSelected(false); setRecommendations([]); }}
            className="px-3 py-2 text-sm bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition flex items-center gap-1"
          >
            <FaTimes className="text-xs" /> Change Level
          </button>
          <button
            onClick={handleFreshFetch}
            disabled={loading}
            className="px-4 py-2 text-sm bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:bg-gray-400 transition flex items-center gap-2"
          >
            <FaSyncAlt className={loading ? 'animate-spin' : ''} /> Fetch Fresh Jobs
          </button>
        </div>
      </div>

      {/* Stats Row */}
      {stats && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-6">
          <div className="bg-gradient-to-br from-green-50 to-green-100 p-3 rounded-xl border border-green-200">
            <div className="text-xs text-gray-500">Matched Jobs</div>
            <div className="text-2xl font-bold text-green-700">{pagination.totalJobs}</div>
          </div>
          <div className="bg-gradient-to-br from-orange-50 to-orange-100 p-3 rounded-xl border border-orange-200">
            <div className="text-xs text-gray-500">Page</div>
            <div className="text-2xl font-bold text-orange-700">
              {pagination.currentPage}/{pagination.totalPages || 1}
            </div>
          </div>
        </div>
      )}

      {/* ─── FILTERS BAR ─── */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5 mb-6">
        <div className="flex items-center gap-2 mb-4">
          <FaFilter className="text-gray-400" />
          <h2 className="text-lg font-semibold text-gray-800">Filters</h2>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-4">
          {/* Location */}
          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1">Location</label>
            <div className="relative">
              <FaMapMarkerAlt className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-xs" />
              <input
                type="text"
                placeholder="e.g. Remote, NYC"
                value={filters.location}
                onChange={(e) => handleFilterChange('location', e.target.value)}
                className="w-full pl-8 pr-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>
          </div>

          {/* Job Type */}
          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1">Job Type</label>
            <select
              value={filters.jobType}
              onChange={(e) => handleFilterChange('jobType', e.target.value)}
              className="w-full px-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
            >
              <option value="all">All Types</option>
              <option value="Full-time">Full-time</option>
              <option value="Part-time">Part-time</option>
              <option value="Contract">Contract</option>
              <option value="Freelance">Freelance</option>
              <option value="Internship">Internship</option>
            </select>
          </div>

          {/* Sort By */}
          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1">Sort By</label>
            <select
              value={filters.sortBy}
              onChange={(e) => handleFilterChange('sortBy', e.target.value)}
              className="w-full px-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
            >
              <option value="score">Match Score</option>
              <option value="date">Newest First</option>
              <option value="company">Company Name</option>
            </select>
          </div>

          {/* Per Page */}
          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1">Results per Page</label>
            <select
              value={filters.perPage}
              onChange={(e) => handleFilterChange('perPage', parseInt(e.target.value))}
              className="w-full px-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
            >
              <option value={10}>10</option>
              <option value={20}>20</option>
              <option value={50}>50</option>
            </select>
          </div>

          {/* Apply Button */}
          <div className="flex items-end">
            <button
              onClick={handleApplyFilters}
              disabled={loading}
              className="w-full px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 disabled:bg-gray-400 transition flex items-center justify-center gap-2"
            >
              <FaSearch className="text-xs" /> Apply Filters
            </button>
          </div>
        </div>

        {/* Experience level pills */}
        <div className="flex items-center gap-2 pt-3 border-t border-gray-100">
          <span className="text-xs font-medium text-gray-500">Experience:</span>
          <button
            onClick={() => { handleFilterChange('experienceLevel', 'fresher'); }}
            className={`px-3 py-1 text-xs font-medium rounded-full transition ${filters.experienceLevel === 'fresher'
              ? 'bg-blue-600 text-white'
              : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
          >
            👨‍🎓 Fresher
          </button>
          <button
            onClick={() => { handleFilterChange('experienceLevel', 'experienced'); }}
            className={`px-3 py-1 text-xs font-medium rounded-full transition ${filters.experienceLevel === 'experienced'
              ? 'bg-indigo-600 text-white'
              : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
          >
            👔 Experienced
          </button>
        </div>
      </div>

      {/* ─── ERROR ─── */}
      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6 flex items-center gap-2">
          <span>⚠️</span> {error}
        </div>
      )}

      {/* ─── LOADING ─── */}
      {loading && (
        <div className="text-center py-16">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-4 border-blue-200 border-t-blue-600"></div>
          <p className="mt-4 text-gray-500">Matching jobs to your resume...</p>
        </div>
      )}

      {/* ─── JOB CARDS ─── */}
      {!loading && recommendations.length > 0 && (
        <div>
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-bold text-gray-900">
              ✨ Top Matches for You
              <span className="text-sm font-normal text-gray-500 ml-2">
                Showing {((pagination.currentPage - 1) * pagination.perPage) + 1}–{Math.min(pagination.currentPage * pagination.perPage, pagination.totalJobs)} of {pagination.totalJobs}
              </span>
            </h2>
          </div>

          <div className="space-y-3">
            {recommendations.map((job) => (
              <div
                key={job.jobId}
                onClick={() => setSelectedJob(selectedJob?.jobId === job.jobId ? null : job)}
                className={`bg-white border rounded-xl p-5 cursor-pointer transition-all duration-200 hover:shadow-md ${selectedJob?.jobId === job.jobId
                  ? 'border-blue-400 shadow-lg ring-1 ring-blue-200'
                  : 'border-gray-200 hover:border-blue-300'
                  }`}
              >
                {/* Job Header Row */}
                <div className="flex items-start justify-between gap-4">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1 flex-wrap">
                      <span className="inline-flex items-center justify-center w-7 h-7 rounded-full bg-gray-100 text-xs font-bold text-gray-600">
                        #{job.rank}
                      </span>
                      <h3 className="text-lg font-bold text-gray-900 truncate">{job.title}</h3>
                    </div>
                    <div className="flex items-center gap-3 text-sm text-gray-500 flex-wrap">
                      <span className="flex items-center gap-1">
                        <FaBuilding className="text-xs" /> {job.company}
                      </span>
                      <span className="flex items-center gap-1">
                        <FaMapMarkerAlt className="text-xs" /> {job.location}
                      </span>
                      {job.experience && (
                        <span className="flex items-center gap-1">
                          <FaClock className="text-xs" /> {job.experience}
                        </span>
                      )}
                    </div>
                  </div>

                  {/* Match Score Badge */}
                  <div className={`flex flex-col items-center p-2 rounded-lg border ${getScoreColor(job.matchScore).bg} ${getScoreColor(job.matchScore).border}`}>
                    <div className="text-xs text-gray-500 font-medium">Match</div>
                    <div className={`text-xl font-bold ${getScoreColor(job.matchScore).text}`}>
                      {job.matchScore}%
                    </div>
                  </div>
                </div>

                {/* Tags */}
                <div className="flex flex-wrap gap-2 mt-3">
                  <span className="text-xs px-2 py-1 bg-gray-100 text-gray-600 rounded-md font-medium">
                    {job.jobType}
                  </span>
                  {job.source && (
                    <span className="text-xs px-2 py-1 bg-blue-50 text-blue-600 rounded-md font-medium">
                      {job.source}
                    </span>
                  )}
                  {job.salaryRange && job.salaryRange.min && (
                    <span className="text-xs px-2 py-1 bg-green-50 text-green-600 rounded-md font-medium">
                      💰 {job.salaryRange.currency || '$'}{job.salaryRange.min?.toLocaleString()}–{job.salaryRange.max?.toLocaleString()}
                    </span>
                  )}
                </div>

                {/* Expandable Details */}
                {selectedJob?.jobId === job.jobId && (
                  <div className="border-t border-gray-100 pt-4 mt-4 space-y-4 animate-fadeIn">
                    {/* Description — rendered as HTML since APIs return HTML content */}
                    {job.description && (
                      <div>
                        <h4 className="font-semibold text-gray-800 mb-2 text-sm">📝 Job Description</h4>
                        <div
                          className="text-sm text-gray-600 leading-relaxed job-description-html max-h-80 overflow-y-auto pr-2"
                          style={{
                            '--tw-prose-body': '#4b5563',
                          }}
                          dangerouslySetInnerHTML={{
                            __html: job.description.length > 2000
                              ? job.description.substring(0, 2000) + '...'
                              : job.description
                          }}
                        />
                      </div>
                    )}

                    {/* Skills */}
                    {job.requiredSkills?.length > 0 && (
                      <div>
                        <h4 className="font-semibold text-gray-800 mb-2 text-sm">🛠️ Required Skills</h4>
                        <div className="flex flex-wrap gap-2">
                          {job.requiredSkills.map((skill, idx) => (
                            <span key={idx} className="text-xs px-2 py-1 bg-purple-50 text-purple-700 rounded-md font-medium border border-purple-200">
                              {skill}
                            </span>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Apply Button */}
                    {job.sourceUrl && (
                      <a
                        href={job.sourceUrl}
                        target="_blank"
                        rel="noopener noreferrer"
                        onClick={(e) => e.stopPropagation()}
                        className="inline-flex items-center gap-2 w-full justify-center bg-blue-600 text-white py-2.5 rounded-lg font-semibold hover:bg-blue-700 transition text-sm"
                      >
                        View & Apply <FaExternalLinkAlt className="text-xs" />
                      </a>
                    )}
                  </div>
                )}

                {/* Click hint */}
                {selectedJob?.jobId !== job.jobId && (
                  <div className="text-xs text-blue-500 mt-2 font-medium">Click to view details →</div>
                )}
              </div>
            ))}
          </div>

          {/* ─── PAGINATION ─── */}
          {pagination.totalPages > 1 && (
            <div className="flex items-center justify-center gap-1 mt-8 mb-4">
              {/* First page */}
              <button
                onClick={() => goToPage(1)}
                disabled={!pagination.hasPrevPage}
                className="p-2 rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed transition"
                title="First page"
              >
                <FaAngleDoubleLeft className="text-sm" />
              </button>

              {/* Previous */}
              <button
                onClick={() => goToPage(pagination.currentPage - 1)}
                disabled={!pagination.hasPrevPage}
                className="p-2 rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed transition"
                title="Previous page"
              >
                <FaChevronLeft className="text-sm" />
              </button>

              {/* Page numbers */}
              {getPageNumbers().map((pageNum, idx) => (
                <React.Fragment key={idx}>
                  {pageNum === '...' ? (
                    <span className="px-2 py-1 text-gray-400">…</span>
                  ) : (
                    <button
                      onClick={() => goToPage(pageNum)}
                      className={`min-w-[36px] h-9 rounded-lg text-sm font-medium transition ${pageNum === pagination.currentPage
                        ? 'bg-blue-600 text-white shadow-sm'
                        : 'border border-gray-200 text-gray-600 hover:bg-gray-100'
                        }`}
                    >
                      {pageNum}
                    </button>
                  )}
                </React.Fragment>
              ))}

              {/* Next */}
              <button
                onClick={() => goToPage(pagination.currentPage + 1)}
                disabled={!pagination.hasNextPage}
                className="p-2 rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed transition"
                title="Next page"
              >
                <FaChevronRight className="text-sm" />
              </button>

              {/* Last page */}
              <button
                onClick={() => goToPage(pagination.totalPages)}
                disabled={!pagination.hasNextPage}
                className="p-2 rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed transition"
                title="Last page"
              >
                <FaAngleDoubleRight className="text-sm" />
              </button>
            </div>
          )}

          {/* Page info text */}
          {pagination.totalPages > 1 && (
            <p className="text-center text-sm text-gray-400">
              Page {pagination.currentPage} of {pagination.totalPages} • {pagination.totalJobs} total jobs matched
            </p>
          )}
        </div>
      )}

      {/* ─── NO RESULTS ─── */}
      {!loading && !initialLoad && recommendations.length === 0 && !error && (
        <div className="text-center py-16 bg-gray-50 rounded-xl border-2 border-dashed border-gray-300">
          <div className="text-5xl mb-3">🔍</div>
          <p className="text-gray-600 mb-2 font-medium">No jobs found matching your filters</p>
          <p className="text-sm text-gray-400 mb-4">Try changing your filters or fetch fresh jobs</p>
          <button
            onClick={handleFreshFetch}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition text-sm font-medium"
          >
            Fetch Fresh Job Listings
          </button>
        </div>
      )}
    </div>
  );
};

export default JobRecommendations;

import React, { useState } from 'react';
import { useDropzone } from 'react-dropzone';
import { FaUpload, FaFilePdf, FaTimes, FaSpinner } from 'react-icons/fa';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import { API_BASE_URL } from '../config/api.js';

const PDFUpload = ({ onDataExtracted, theme }) => {
  const { user } = useAuth();
  const [uploadedFile, setUploadedFile] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState('');

  const onDrop = async (acceptedFiles) => {
    const file = acceptedFiles[0];
    if (file && file.type === 'application/pdf') {
      setUploadedFile(file);
      setError('');
      await processFile(file);
    } else {
      setError('Please upload a valid PDF file');
    }
  };

  const processFile = async (file) => {
    setIsProcessing(true);
    setError('');

    try {
      if (!user || !user.sessionId) {
        setError('Please log in to upload a resume');
        return;
      }

      const formData = new FormData();
      formData.append('pdf', file);

      // Use the smart portfolio endpoint with enhanced resume processing
      const response = await axios.post(`${API_BASE_URL}/api/smart/user/${user.sessionId}/portfolio`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      if (response.data.success) {
        // Smart portfolio data is already in the correct format
        onDataExtracted(response.data.portfolio);
      } else {
        setError('Failed to process PDF');
      }
    } catch (error) {
      console.error('Error processing PDF:', error);
      const errorMessage = error.response?.data?.message || 'Error processing PDF. Please try again.';
      setError(errorMessage);
    } finally {
      setIsProcessing(false);
    }
  };

  const removeFile = () => {
    setUploadedFile(null);
    setError('');
  };



  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'application/pdf': ['.pdf']
    },
    maxFiles: 1,
    disabled: isProcessing
  });

  return (
    <div className="mb-8">
      <h2 className="text-blue-600 dark:text-blue-400 text-2xl md:text-3xl mb-6 relative pb-2 after:content-[''] after:absolute after:bottom-0 after:left-0 after:w-12 after:h-1 after:bg-blue-600 dark:after:bg-blue-400">
        Upload Resume
      </h2>

      {!uploadedFile ? (
        <div
          {...getRootProps()}
          className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all duration-300 ${isDragActive
            ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20'
            : 'border-gray-300 dark:border-gray-600 hover:border-blue-400 dark:hover:border-blue-500'
            } ${isProcessing ? 'opacity-50 cursor-not-allowed' : ''}`}
        >
          <input {...getInputProps()} />
          <div className="flex flex-col items-center">
            <FaUpload className="text-4xl text-gray-400 dark:text-gray-500 mb-4" />
            <p className="text-lg font-medium text-gray-700 dark:text-gray-300 mb-2">
              {isDragActive ? 'Drop your resume here' : 'Upload your resume'}
            </p>
            <p className="text-sm text-gray-500 dark:text-gray-400">
              Drag and drop a PDF file here, or click to select
            </p>
          </div>
        </div>
      ) : (
        <div className="bg-gray-50 dark:bg-gray-700 rounded-xl p-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center">
              <FaFilePdf className="text-red-500 text-2xl mr-3" />
              <div>
                <p className="font-medium text-gray-900 dark:text-gray-100">
                  {uploadedFile.name}
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400">
                  {(uploadedFile.size / 1024 / 1024).toFixed(2)} MB
                </p>
              </div>
            </div>
            {isProcessing ? (
              <div className="flex items-center text-blue-600 dark:text-blue-400">
                <FaSpinner className="animate-spin mr-2" />
                <span>Processing...</span>
              </div>
            ) : (
              <button
                onClick={removeFile}
                className="text-red-500 hover:text-red-700 transition-colors duration-200"
              >
                <FaTimes className="text-xl" />
              </button>
            )}
          </div>
        </div>
      )}

      {error && (
        <div className="mt-4 p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg">
          <p className="text-red-600 dark:text-red-400 text-sm">{error}</p>
        </div>
      )}
    </div>
  );
};

export default PDFUpload;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { FaEye, FaEdit, FaTrash, FaCopy, FaShare, FaDownload, FaPalette, FaCog, FaArrowLeft, FaExclamationTriangle, FaGlobe, FaEnvelope, FaPhone, FaTwitter, FaLinkedin, FaGithub } from 'react-icons/fa';
import { useAuth } from '../context/AuthContext.jsx';
import portfolioService from '../services/portfolioService.js';
import { API_BASE_URL } from '../config/api.js';
import { getThemeColors } from '../utils/themes';
import PortfolioCustomizer from './PortfolioCustomizer.jsx';
import PortfolioEditModal from './PortfolioEditModal.jsx';

const PortfolioDisplay = ({ portfolio: propPortfolio, onEdit, onDelete, onDuplicate }) => {
    const { user, loading: authLoading } = useAuth();
    const { portfolioId, slug } = useParams();
    const navigate = useNavigate();

    // State for portfolio data
    const [portfolio, setPortfolio] = useState(propPortfolio);
    const [loading, setLoading] = useState(!propPortfolio);
    const [error, setError] = useState(null);
    const [isPublished, setIsPublished] = useState(portfolio?.isPublished || false);
    const [isUpdating, setIsUpdating] = useState(false);
    const [isUploadingPhoto, setIsUploadingPhoto] = useState(false);
    const fileInputRef = useRef(null);

    // Local edit state
    const [isEditing, setIsEditing] = useState(false);
    const [saving, setSaving] = useState(false);
    const [editData, setEditData] = useState(null);

    // Customization state
    const [customization, setCustomization] = useState({
        template: 'modern-clean',
        theme: { name: 'Ocean Blue', gradient: 'from-blue-500 to-cyan-400', bg: 'bg-blue-50' },
        colors: {
            heading: '#000000',
            subheading: '#333333',
            paragraph: '#555555',
            headerBg: '#ffffff',
            bodyBg: '#f9f9f9',
        }
    });

    // Debug: Log customization changes
    useEffect(() => {
        console.log('Customization state updated:', customization);
    }, [customization]);

    // Fetch portfolio data if not provided as prop
    useEffect(() => {
        const fetchPortfolio = async () => {
            if (propPortfolio) {
                setPortfolio(propPortfolio);
                setLoading(false);
                return;
            }

            if (!portfolioId && !slug) {
                setError('No portfolio identifier provided');
                setLoading(false);
                return;
            }

            try {
                setLoading(true);
                let response;

                if (portfolioId) {
                    if (!user || !user.sessionId) {
                        setError('User not authenticated');
                        setLoading(false);
                        return;
                    }
                    response = await portfolioService.getPortfolio(user.sessionId, portfolioId);
                } else if (slug) {
                    response = await portfolioService.getPublicPortfolio(slug);
                }

                if (response.success && response.portfolio) {
                    setPortfolio(response.portfolio);
                    setIsPublished(response.portfolio.isPublished);
                } else {
                    setError('Portfolio not found');
                }
            } catch (err) {
                setError(err.message || 'Failed to load portfolio');
            } finally {
                setLoading(false);
            }
        };

        fetchPortfolio();
    }, [propPortfolio, portfolioId, slug, user]);

    // When portfolio changes, reset edit buffer
    useEffect(() => {
        if (portfolio) {
            setEditData({
                header: {
                    name: portfolio.header?.name || '',
                    shortAbout: portfolio.header?.shortAbout || '',
                    location: portfolio.header?.location || '',
                    contacts: {
                        website: portfolio.header?.contacts?.website || '',
                        email: portfolio.header?.contacts?.email || '',
                        phone: portfolio.header?.contacts?.phone || '',
                        twitter: portfolio.header?.contacts?.twitter || '',
                        linkedin: portfolio.header?.contacts?.linkedin || '',
                        github: portfolio.header?.contacts?.github || ''
                    },
                    skills: Array.isArray(portfolio.header?.skills) ? portfolio.header.skills : []
                },
                summary: portfolio.summary || '',
                workExperience: Array.isArray(portfolio.workExperience) ? portfolio.workExperience.map(w => ({ ...w })) : [],
                education: Array.isArray(portfolio.education) ? portfolio.education.map(e => ({ ...e })) : [],
                extraSections: Array.isArray(portfolio.extraSections) ? portfolio.extraSections.map(s => ({
                    key: s.key,
                    title: s.title,
                    items: Array.isArray(s.items) ? s.items.map(i => ({ ...i })) : []
                })) : []
            });
        }
    }, [portfolio]);

    const handleStartEdit = () => {
        setIsEditing(true);
    };

    const handleSaveEditModal = async (updatedData) => {
        if (!user || !portfolio) return;
        try {
            const resp = await portfolioService.updatePortfolio(user.sessionId, portfolio._id, updatedData);
            if (resp.success && resp.portfolio) {
                setPortfolio(resp.portfolio);
                setIsEditing(false);
            }
        } catch (e) {
            console.error('Failed to save edits', e);
            throw e;
        }
    };

    const handleSaveAndDashboard = async () => {
        if (!user || !portfolio) return;
        setIsUpdating(true);
        try {
            // If there are unsaved edits, save them first
            if (isEditing && editData) {
                await handleSaveEditModal(editData);
            }
            // Navigate to dashboard
            navigate('/dashboard');
        } catch (error) {
            console.error('Failed to save:', error);
        } finally {
            setIsUpdating(false);
        }
    };

    const [deployedLink, setDeployedLink] = useState(null);
    const [isDeploying, setIsDeploying] = useState(false);
    const [showDeployModal, setShowDeployModal] = useState(false);

    const handleDeploy = async () => {
        if (!user || !portfolio) return;
        setIsDeploying(true);
        try {
            // First, ensure portfolio is published
            if (!isPublished) {
                const response = await portfolioService.togglePublish(user.sessionId, portfolio._id, true);
                if (response.success) {
                    setIsPublished(true);
                }
            }
            // Generate public link using urlSlug
            const slug = portfolio.urlSlug || portfolio._id;
            const publicLink = `${window.location.origin}/p/${slug}`;
            setDeployedLink(publicLink);
            setShowDeployModal(true);
        } catch (error) {
            console.error('Failed to deploy:', error);
            alert('Failed to deploy portfolio. Please try again.');
        } finally {
            setIsDeploying(false);
        }
    };

    const copyDeployLink = () => {
        if (deployedLink) {
            navigator.clipboard.writeText(deployedLink);
            alert('Link copied to clipboard!');
        }
    };

    const handleCancelEdit = () => {
        // Reset edits to current portfolio values
        if (portfolio) {
            setEditData({
                header: {
                    name: portfolio.header?.name || '',
                    shortAbout: portfolio.header?.shortAbout || '',
                    location: portfolio.header?.location || '',
                    contacts: {
                        website: portfolio.header?.contacts?.website || '',
                        email: portfolio.header?.contacts?.email || '',
                        phone: portfolio.header?.contacts?.phone || '',
                        twitter: portfolio.header?.contacts?.twitter || '',
                        linkedin: portfolio.header?.contacts?.linkedin || '',
                        github: portfolio.header?.contacts?.github || ''
                    },
                    skills: Array.isArray(portfolio.header?.skills) ? portfolio.header.skills : []
                },
                summary: portfolio.summary || ''
            });
        }
        setIsEditing(false);
    };

    const handleSaveEdit = async () => {
        if (!user || !portfolio) return;
        setSaving(true);
        try {
            const payload = {
                header: {
                    ...(portfolio.header || {}),
                    name: editData.header.name,
                    shortAbout: editData.header.shortAbout,
                    location: editData.header.location,
                    contacts: { ...(portfolio.header?.contacts || {}), ...editData.header.contacts },
                    skills: Array.isArray(editData.header.skills) ? editData.header.skills : []
                },
                summary: editData.summary,
                workExperience: Array.isArray(editData.workExperience) ? editData.workExperience : [],
                education: Array.isArray(editData.education) ? editData.education : [],
                extraSections: Array.isArray(editData.extraSections) ? editData.extraSections : []
            };
            const resp = await portfolioService.updatePortfolio(user.sessionId, portfolio._id, payload);
            if (resp.success && resp.portfolio) {
                setPortfolio(resp.portfolio);
                setIsEditing(false);
            }
        } catch (e) {
            console.error('Failed to save edits', e);
        } finally {
            setSaving(false);
        }
    };

    // Helpers to update arrays
    const updateWorkField = (index, key, value) => {
        setEditData(prev => {
            const list = [...(prev.workExperience || [])];
            list[index] = { ...(list[index] || {}), [key]: value };
            return { ...prev, workExperience: list };
        });
    };

    const addWorkItem = () => {
        setEditData(prev => ({
            ...prev,
            workExperience: [...(prev.workExperience || []), { company: '', link: '', location: '', contract: '', title: '', start: '', end: '', description: '' }]
        }));
    };

    const removeWorkItem = (index) => {
        setEditData(prev => ({
            ...prev,
            workExperience: (prev.workExperience || []).filter((_, i) => i !== index)
        }));
    };

    const updateEduField = (index, key, value) => {
        setEditData(prev => {
            const list = [...(prev.education || [])];
            list[index] = { ...(list[index] || {}), [key]: value };
            return { ...prev, education: list };
        });
    };

    const addEduItem = () => {
        setEditData(prev => ({
            ...prev,
            education: [...(prev.education || []), { school: '', degree: '', start: '', end: '' }]
        }));
    };

    const removeEduItem = (index) => {
        setEditData(prev => ({
            ...prev,
            education: (prev.education || []).filter((_, i) => i !== index)
        }));
    };

    const updateExtraSectionTitle = (sIdx, title) => {
        setEditData(prev => {
            const sections = [...(prev.extraSections || [])];
            sections[sIdx] = { ...(sections[sIdx] || {}), title };
            return { ...prev, extraSections: sections };
        });
    };

    const addExtraSection = () => {
        setEditData(prev => ({
            ...prev,
            extraSections: [...(prev.extraSections || []), { key: `custom-${Date.now()}`, title: 'New Section', items: [] }]
        }));
    };

    const removeExtraSection = (sIdx) => {
        setEditData(prev => ({
            ...prev,
            extraSections: (prev.extraSections || []).filter((_, i) => i !== sIdx)
        }));
    };

    const addExtraItem = (sIdx) => {
        setEditData(prev => {
            const sections = [...(prev.extraSections || [])];
            const items = [...(sections[sIdx]?.items || [])];
            items.push({ title: '', name: '', description: '', link: '', year: '', venue: '', tech: [] });
            sections[sIdx] = { ...(sections[sIdx] || {}), items };
            return { ...prev, extraSections: sections };
        });
    };

    const removeExtraItem = (sIdx, iIdx) => {
        setEditData(prev => {
            const sections = [...(prev.extraSections || [])];
            const items = (sections[sIdx]?.items || []).filter((_, idx) => idx !== iIdx);
            sections[sIdx] = { ...(sections[sIdx] || {}), items };
            return { ...prev, extraSections: sections };
        });
    };

    const updateExtraItemField = (sIdx, iIdx, key, value) => {
        setEditData(prev => {
            const sections = [...(prev.extraSections || [])];
            const items = [...(sections[sIdx]?.items || [])];
            items[iIdx] = { ...(items[iIdx] || {}), [key]: value };
            sections[sIdx] = { ...(sections[sIdx] || {}), items };
            return { ...prev, extraSections: sections };
        });
    };

    const handleTogglePublish = async () => {
        if (!portfolio) return;

        setIsUpdating(true);
        try {
            const response = await portfolioService.togglePublish(user.sessionId, portfolio._id, !isPublished);
            if (response.success) {
                setIsPublished(!isPublished);
            }
        } catch (error) {
            console.error('Failed to update publish status:', error);
        } finally {
            setIsUpdating(false);
        }
    };

    const openPhotoPicker = () => {
        if (fileInputRef.current) fileInputRef.current.click();
    };

    const handlePhotoSelected = async (e) => {
        if (!portfolio || !user) return;
        const file = e.target.files?.[0];
        if (!file) return;
        setIsUploadingPhoto(true);
        try {
            const response = await portfolioService.uploadPortfolioPhoto(user.sessionId, portfolio._id, file);
            if (response.success && response.photoUrl) {
                setPortfolio({ ...portfolio, header: { ...(portfolio.header || {}), photoUrl: response.photoUrl } });
            }
        } catch (err) {
            console.error('Failed to upload photo:', err);
        } finally {
            setIsUploadingPhoto(false);
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    const handleApplyCustomization = (customizationData) => {
        console.log('PortfolioDisplay received customization:', customizationData);
        if (customizationData.type === 'template') {
            console.log('Setting template to:', customizationData.value);
            setCustomization(prev => {
                const newState = { ...prev, template: customizationData.value };
                console.log('New customization state:', newState);
                return newState;
            });
        } else if (customizationData.type === 'theme') {
            setCustomization(prev => ({ ...prev, theme: customizationData.value }));
        } else if (customizationData.type === 'color') {
            setCustomization(prev => ({ ...prev, colors: customizationData.value }));
        }
    };

    // Check if auth is still loading
    if (authLoading) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center">
                <div className="text-center">
                    <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-purple-600 mx-auto mb-4"></div>
                    <p className="text-gray-600 text-lg">Loading Authentication...</p>
                </div>
            </div>
        );
    }

    // Check authentication for portfolio ID routes
    if (portfolioId && (!user || !user.sessionId)) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center">
                <div className="text-center">
                    <div className="mx-auto h-24 w-24 bg-red-100 rounded-full flex items-center justify-center mb-4">
                        <FaExclamationTriangle className="h-12 w-12 text-red-600" />
                    </div>
                    <h2 className="text-2xl font-bold text-gray-900 mb-2">Authentication Required</h2>
                    <p className="text-gray-600 mb-4">Please log in to view this portfolio.</p>
                    <button
                        onClick={() => navigate('/login')}
                        className="px-6 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors flex items-center gap-2 mx-auto"
                    >
                        Go to Login
                    </button>
                </div>
            </div>
        );
    }

    // Loading state
    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center">
                <div className="text-center">
                    <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-purple-600 mx-auto mb-4"></div>
                    <p className="text-gray-600 text-lg">Loading Portfolio...</p>
                </div>
            </div>
        );
    }

    // Error state
    if (error) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center">
                <div className="text-center">
                    <div className="mx-auto h-24 w-24 bg-red-100 rounded-full flex items-center justify-center mb-4">
                        <FaExclamationTriangle className="h-12 w-12 text-red-600" />
                    </div>
                    <h2 className="text-2xl font-bold text-gray-900 mb-2">Error Loading Portfolio</h2>
                    <p className="text-gray-600 mb-4">{error}</p>
                    <button
                        onClick={() => navigate('/dashboard')}
                        className="px-6 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors flex items-center gap-2 mx-auto"
                    >
                        <FaArrowLeft />
                        Back to Dashboard
                    </button>
                </div>
            </div>
        );
    }

    // No portfolio data
    if (!portfolio) {
        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center">
                <div className="text-center">
                    <div className="mx-auto h-24 w-24 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                        <FaExclamationTriangle className="h-12 w-12 text-gray-600" />
                    </div>
                    <h2 className="text-2xl font-bold text-gray-900 mb-2">Portfolio Not Found</h2>
                    <p className="text-gray-600 mb-4">The requested portfolio could not be found.</p>
                    <button
                        onClick={() => navigate('/dashboard')}
                        className="px-6 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors flex items-center gap-2 mx-auto"
                    >
                        <FaArrowLeft />
                        Back to Dashboard
                    </button>
                </div>
            </div>
        );
    }

    // Theme values
    const themeName = portfolio?.themeKey || 'modern';
    const theme = getThemeColors(themeName, 'light');

    return (
        <div className="min-h-screen" style={{ backgroundColor: customization.colors.bodyBg }}>
            {/* Customization Header - Only show for portfolio ID routes */}
            {portfolioId && <PortfolioCustomizer onApplyCustomization={handleApplyCustomization} />}
            
            {/* Header */}
            <div 
                className={`bg-gradient-to-br ${customization.theme.gradient} text-white shadow-lg`}
                style={{ backgroundColor: customization.colors.headerBg }}
            >
                <div className="max-w-7xl mx-auto px-4 py-8">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-6">
                            {portfolio.header?.photoUrl && (
                                <img
                                    src={
                                        portfolio.header.photoUrl.startsWith('http')
                                            ? portfolio.header.photoUrl
                                            : `${API_BASE_URL}${portfolio.header.photoUrl}`
                                    }
                                    alt={portfolio.header?.name || 'Profile'}
                                    className="w-20 h-20 rounded-full object-cover border-2 border-white shadow"
                                />
                            )}
                            <div>
                                <h1 
                                    className="text-3xl font-bold" 
                                    style={{ color: customization.colors.heading }}
                                >
                                    {portfolio.header?.name || portfolio.title}
                                </h1>
                                <p 
                                    className="opacity-90 mt-2"
                                    style={{ color: customization.colors.subheading }}
                                >
                                    {portfolio.header?.shortAbout || 'Professional Portfolio'}
                                </p>
                                {portfolio.header?.location && (
                                    <p 
                                        className="opacity-80 mt-1"
                                        style={{ color: customization.colors.paragraph }}
                                    >
                                        📍 {portfolio.header.location}
                                    </p>
                                )}
                            </div>
                        </div>

                        {portfolioId && (
                            <div className="flex items-center gap-3">
                                <input
                                    ref={fileInputRef}
                                    type="file"
                                    accept="image/png,image/jpeg,image/webp"
                                    className="hidden"
                                    onChange={handlePhotoSelected}
                                />
                                <button
                                    onClick={openPhotoPicker}
                                    disabled={isUploadingPhoto}
                                    className={`px-4 py-2 rounded-lg font-medium transition-colors shadow-md ${
                                        isUploadingPhoto 
                                            ? 'bg-gray-400 text-white cursor-not-allowed' 
                                            : 'bg-white hover:bg-gray-50'
                                    }`}
                                    style={{ color: isUploadingPhoto ? '#fff' : customization.colors.heading }}
                                >
                                    {isUploadingPhoto ? 'Uploading...' : (portfolio.header?.photoUrl ? 'Change Photo' : 'Upload Photo')}
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Portfolio Content */}
            <div className="max-w-7xl mx-auto px-4 py-8">
                <div 
                    className={`rounded-lg shadow-sm border template-${customization.template} ${customization.theme.bg}`}
                    style={{ 
                        backgroundColor: customization.colors.bodyBg,
                        borderColor: customization.colors.paragraph + '40'
                    }}
                >
                    {/* Simple inline editor for key fields */}
                    {isEditing && editData && (
                        <div className={`p-6 border-b ${theme.border.light}`}>
                            <h2 className={`text-xl font-semibold mb-4 ${theme.text.primary.light}`}>Edit Basics</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm text-gray-600 mb-1">Name</label>
                                    <input
                                        value={editData.header.name}
                                        onChange={(e) => setEditData({ ...editData, header: { ...editData.header, name: e.target.value } })}
                                        className="w-full border rounded px-3 py-2"
                                        placeholder="Full name"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm text-gray-600 mb-1">Tagline</label>
                                    <input
                                        value={editData.header.shortAbout}
                                        onChange={(e) => setEditData({ ...editData, header: { ...editData.header, shortAbout: e.target.value } })}
                                        className="w-full border rounded px-3 py-2"
                                        placeholder="Professional tagline"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm text-gray-600 mb-1">Location</label>
                                    <input
                                        value={editData.header.location}
                                        onChange={(e) => setEditData({ ...editData, header: { ...editData.header, location: e.target.value } })}
                                        className="w-full border rounded px-3 py-2"
                                        placeholder="City, Country"
                                    />
                                </div>
                                <div className="md:col-span-2">
                                    <label className="block text-sm text-gray-600 mb-1">Summary</label>
                                    <textarea
                                        value={editData.summary}
                                        onChange={(e) => setEditData({ ...editData, summary: e.target.value })}
                                        className="w-full border rounded px-3 py-2 min-h-[100px]"
                                        placeholder="Professional summary"
                                    />
                                </div>
                                <div className="md:col-span-2">
                                    <label className="block text-sm text-gray-600 mb-1">Skills (comma separated)</label>
                                    <input
                                        value={(editData.header.skills || []).join(', ')}
                                        onChange={(e) => setEditData({ ...editData, header: { ...editData.header, skills: e.target.value.split(',').map(s => s.trim()).filter(Boolean) } })}
                                        className="w-full border rounded px-3 py-2"
                                        placeholder="JavaScript, React, Node.js"
                                    />
                                </div>
                            </div>
                            {/* Contacts */}
                            <div className="mt-6">
                                <h3 className={`text-lg font-semibold mb-3 ${theme.text.primary.light}`}>Contacts</h3>
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                    <div>
                                        <label className="block text-sm text-gray-600 mb-1">Email</label>
                                        <input className="w-full border rounded px-3 py-2" value={editData.header.contacts.email} onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, email: e.target.value } } })} />
                                    </div>
                                    <div>
                                        <label className="block text-sm text-gray-600 mb-1">Phone</label>
                                        <input className="w-full border rounded px-3 py-2" value={editData.header.contacts.phone} onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, phone: e.target.value } } })} />
                                    </div>
                                    <div>
                                        <label className="block text-sm text-gray-600 mb-1">Website</label>
                                        <input className="w-full border rounded px-3 py-2" value={editData.header.contacts.website} onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, website: e.target.value } } })} />
                                    </div>
                                    <div>
                                        <label className="block text-sm text-gray-600 mb-1">LinkedIn</label>
                                        <input className="w-full border rounded px-3 py-2" value={editData.header.contacts.linkedin} onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, linkedin: e.target.value } } })} />
                                    </div>
                                    <div>
                                        <label className="block text-sm text-gray-600 mb-1">GitHub</label>
                                        <input className="w-full border rounded px-3 py-2" value={editData.header.contacts.github} onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, github: e.target.value } } })} />
                                    </div>
                                    <div>
                                        <label className="block text-sm text-gray-600 mb-1">Twitter</label>
                                        <input className="w-full border rounded px-3 py-2" value={editData.header.contacts.twitter} onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, twitter: e.target.value } } })} />
                                    </div>
                                </div>
                            </div>
                            {/* Work Experience */}
                            <div className="mt-8">
                                <div className="flex items-center justify-between mb-3">
                                    <h3 className={`text-lg font-semibold ${theme.text.primary.light}`}>Work Experience</h3>
                                    <button onClick={addWorkItem} className="px-3 py-1 bg-blue-600 text-white rounded text-sm">Add Experience</button>
                                </div>
                                <div className="space-y-4">
                                    {(editData.workExperience || []).map((exp, idx) => (
                                        <div key={idx} className="border rounded p-4">
                                            <div className="flex justify-between items-center mb-3">
                                                <span className="text-sm text-gray-600">Item #{idx + 1}</span>
                                                <button onClick={() => removeWorkItem(idx)} className="px-2 py-1 bg-red-600 text-white rounded text-xs">Remove</button>
                                            </div>
                                            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                                                <input className="border rounded px-3 py-2" placeholder="Company" value={exp.company || ''} onChange={(e) => updateWorkField(idx, 'company', e.target.value)} />
                                                <input className="border rounded px-3 py-2" placeholder="Title" value={exp.title || ''} onChange={(e) => updateWorkField(idx, 'title', e.target.value)} />
                                                <input className="border rounded px-3 py-2" placeholder="Location" value={exp.location || ''} onChange={(e) => updateWorkField(idx, 'location', e.target.value)} />
                                                <input className="border rounded px-3 py-2" placeholder="Contract" value={exp.contract || ''} onChange={(e) => updateWorkField(idx, 'contract', e.target.value)} />
                                                <input className="border rounded px-3 py-2" placeholder="Start" value={exp.start || ''} onChange={(e) => updateWorkField(idx, 'start', e.target.value)} />
                                                <input className="border rounded px-3 py-2" placeholder="End" value={exp.end || ''} onChange={(e) => updateWorkField(idx, 'end', e.target.value)} />
                                                <input className="border rounded px-3 py-2 md:col-span-3" placeholder="Company Link" value={exp.link || ''} onChange={(e) => updateWorkField(idx, 'link', e.target.value)} />
                                                <textarea className="border rounded px-3 py-2 md:col-span-3" placeholder="Description" value={exp.description || ''} onChange={(e) => updateWorkField(idx, 'description', e.target.value)} />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                            {/* Education */}
                            <div className="mt-8">
                                <div className="flex items-center justify-between mb-3">
                                    <h3 className={`text-lg font-semibold ${theme.text.primary.light}`}>Education</h3>
                                    <button onClick={addEduItem} className="px-3 py-1 bg-blue-600 text-white rounded text-sm">Add Education</button>
                                </div>
                                <div className="space-y-4">
                                    {(editData.education || []).map((edu, idx) => (
                                        <div key={idx} className="border rounded p-4">
                                            <div className="flex justify-between items-center mb-3">
                                                <span className="text-sm text-gray-600">Item #{idx + 1}</span>
                                                <button onClick={() => removeEduItem(idx)} className="px-2 py-1 bg-red-600 text-white rounded text-xs">Remove</button>
                                            </div>
                                            <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
                                                <input className="border rounded px-3 py-2" placeholder="School" value={edu.school || ''} onChange={(e) => updateEduField(idx, 'school', e.target.value)} />
                                                <input className="border rounded px-3 py-2" placeholder="Degree" value={edu.degree || ''} onChange={(e) => updateEduField(idx, 'degree', e.target.value)} />
                                                <input className="border rounded px-3 py-2" placeholder="Start" value={edu.start || ''} onChange={(e) => updateEduField(idx, 'start', e.target.value)} />
                                                <input className="border rounded px-3 py-2" placeholder="End" value={edu.end || ''} onChange={(e) => updateEduField(idx, 'end', e.target.value)} />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                            {/* Extra Sections */}
                            <div className="mt-8">
                                <div className="flex items-center justify-between mb-3">
                                    <h3 className={`text-lg font-semibold ${theme.text.primary.light}`}>Extra Sections</h3>
                                    <button onClick={addExtraSection} className="px-3 py-1 bg-blue-600 text-white rounded text-sm">Add Section</button>
                                </div>
                                <div className="space-y-6">
                                    {(editData.extraSections || []).map((section, sIdx) => (
                                        <div key={sIdx} className="border rounded p-4">
                                            <div className="flex items-center justify-between mb-3">
                                                <div className="flex-1 mr-3">
                                                    <input className="w-full border rounded px-3 py-2" placeholder="Section Title" value={section.title || ''} onChange={(e) => updateExtraSectionTitle(sIdx, e.target.value)} />
                                                </div>
                                                <button onClick={() => removeExtraSection(sIdx)} className="px-2 py-1 bg-red-600 text-white rounded text-xs">Remove Section</button>
                                            </div>
                                            <div className="space-y-3">
                                                {(section.items || []).map((item, iIdx) => (
                                                    <div key={iIdx} className="border rounded p-3">
                                                        <div className="flex justify-between items-center mb-2">
                                                            <span className="text-xs text-gray-600">Item #{iIdx + 1}</span>
                                                            <button onClick={() => removeExtraItem(sIdx, iIdx)} className="px-2 py-1 bg-red-500 text-white rounded text-xs">Remove</button>
                                                        </div>
                                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-2">
                                                            <input className="border rounded px-3 py-2" placeholder="Title" value={item.title || ''} onChange={(e) => updateExtraItemField(sIdx, iIdx, 'title', e.target.value)} />
                                                            <input className="border rounded px-3 py-2" placeholder="Name" value={item.name || ''} onChange={(e) => updateExtraItemField(sIdx, iIdx, 'name', e.target.value)} />
                                                            <input className="border rounded px-3 py-2" placeholder="Link" value={item.link || ''} onChange={(e) => updateExtraItemField(sIdx, iIdx, 'link', e.target.value)} />
                                                            <input className="border rounded px-3 py-2" placeholder="Venue" value={item.venue || ''} onChange={(e) => updateExtraItemField(sIdx, iIdx, 'venue', e.target.value)} />
                                                            <input className="border rounded px-3 py-2" placeholder="Year" value={item.year || ''} onChange={(e) => updateExtraItemField(sIdx, iIdx, 'year', e.target.value)} />
                                                            <input className="border rounded px-3 py-2 md:col-span-3" placeholder="Tech (comma separated)" value={Array.isArray(item.tech) ? item.tech.join(', ') : ''} onChange={(e) => updateExtraItemField(sIdx, iIdx, 'tech', e.target.value.split(',').map(t => t.trim()).filter(Boolean))} />
                                                            <textarea className="border rounded px-3 py-2 md:col-span-3" placeholder="Description" value={item.description || ''} onChange={(e) => updateExtraItemField(sIdx, iIdx, 'description', e.target.value)} />
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                            <div className="mt-3">
                                                <button onClick={() => addExtraItem(sIdx)} className="px-3 py-1 bg-blue-600 text-white rounded text-sm">Add Item</button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}
                    {/* Contact Information */}
                    {portfolio.header?.contacts && (
                        <div className="p-6 border-b" style={{ borderColor: customization.colors.paragraph + '20' }}>
                            <h2 
                                className="text-xl font-semibold mb-4" 
                                style={{ color: customization.colors.heading }}
                            >
                                Contact Information
                            </h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {portfolio.header.contacts.email && (
                                    <div className="flex items-center gap-3">
                                        <FaEnvelope className="text-gray-400" />
                                        <span style={{ color: customization.colors.paragraph }}>{portfolio.header.contacts.email}</span>
                                    </div>
                                )}
                                {portfolio.header.contacts.phone && (
                                    <div className="flex items-center gap-3">
                                        <FaPhone className="text-gray-400" />
                                        <span style={{ color: customization.colors.paragraph }}>{portfolio.header.contacts.phone}</span>
                                    </div>
                                )}
                                {portfolio.header.location && (
                                    <div className="flex items-center gap-3">
                                        <FaGlobe className="text-gray-400" />
                                        <span className={`${theme.text.primary.light}`}>{portfolio.header.location}</span>
                                    </div>
                                )}
                                {portfolio.header.contacts.website && (
                                    <div className="flex items-center gap-3">
                                        <FaGlobe className="text-gray-400" />
                                        <a href={portfolio.header.contacts.website} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:text-blue-800">
                                            {portfolio.header.contacts.website}
                                        </a>
                                    </div>
                                )}
                            </div>

                            {/* Social Links */}
                            <div className="flex gap-4 mt-4">
                                {portfolio.header.contacts.linkedin && (
                                    <a href={`https://linkedin.com/in/${portfolio.header.contacts.linkedin}`} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:text-blue-800">
                                        <FaLinkedin className="w-5 h-5" />
                                    </a>
                                )}
                                {portfolio.header.contacts.github && (
                                    <a href={`https://github.com/${portfolio.header.contacts.github}`} target="_blank" rel="noopener noreferrer" className="text-gray-600 hover:text-gray-800">
                                        <FaGithub className="w-5 h-5" />
                                    </a>
                                )}
                                {portfolio.header.contacts.twitter && (
                                    <a href={`https://twitter.com/${portfolio.header.contacts.twitter}`} target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-600">
                                        <FaTwitter className="w-5 h-5" />
                                    </a>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Summary */}
                    {portfolio.summary && (
                        <div className="p-6 border-b" style={{ borderColor: customization.colors.paragraph + '20' }}>
                            <h2 className="text-xl font-semibold mb-4" style={{ color: customization.colors.heading }}>About</h2>
                            <p className="leading-relaxed" style={{ color: customization.colors.paragraph }}>{portfolio.summary}</p>
                        </div>
                    )}

                    {/* Skills */}
                    {portfolio.header?.skills && portfolio.header.skills.length > 0 && (
                        <div className="p-6 border-b" style={{ borderColor: customization.colors.paragraph + '20' }}>
                            <h2 className="text-xl font-semibold mb-4" style={{ color: customization.colors.heading }}>Skills</h2>
                            <div className="flex flex-wrap gap-2">
                                {portfolio.header.skills.map((skill, index) => (
                                    <span
                                        key={index}
                                        className={`px-3 py-1 rounded-full text-sm font-medium text-white bg-gradient-to-r ${theme.gradients.skills}`}
                                    >
                                        {skill}
                                    </span>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Work Experience */}
                    {portfolio.workExperience && portfolio.workExperience.length > 0 && (
                        <div className="p-6 border-b" style={{ borderColor: customization.colors.paragraph + '20' }}>
                            <h2 className="text-xl font-semibold mb-4" style={{ color: customization.colors.heading }}>Work Experience</h2>
                            <div className="space-y-6">
                                {portfolio.workExperience.map((exp, index) => (
                                    <div key={index} className="border-l-4 pl-4" style={{ borderLeftColor: customization.colors.subheading }}>
                                        <div className="flex justify-between items-start mb-2">
                                            <div>
                                                <h3 className="text-lg font-semibold" style={{ color: customization.colors.subheading }}>{exp.title}</h3>
                                                <p className="font-medium" style={{ color: customization.colors.paragraph }}>{exp.company}</p>
                                                {exp.location && (
                                                    <p className="text-sm" style={{ color: customization.colors.paragraph }}>{exp.location}</p>
                                                )}
                                            </div>
                                            <div className="text-right text-sm" style={{ color: customization.colors.paragraph }}>
                                                <p>{exp.start} - {exp.end}</p>
                                                {exp.contract && (
                                                    <p className="text-xs opacity-80">{exp.contract}</p>
                                                )}
                                            </div>
                                        </div>
                                        <p className="leading-relaxed" style={{ color: customization.colors.paragraph }}>{exp.description}</p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Education */}
                    {portfolio.education && portfolio.education.length > 0 && (
                        <div className="p-6">
                            <h2 className="text-xl font-semibold mb-4" style={{ color: customization.colors.heading }}>Education</h2>
                            <div className="space-y-4">
                                {portfolio.education.map((edu, index) => (
                                    <div key={index} className="border-l-4 pl-4" style={{ borderLeftColor: customization.colors.subheading }}>
                                        <div className="flex justify-between items-start">
                                            <div>
                                                <h3 className="text-lg font-semibold" style={{ color: customization.colors.subheading }}>{edu.degree}</h3>
                                                <p className="font-medium" style={{ color: customization.colors.paragraph }}>{edu.school}</p>
                                            </div>
                                            <div className="text-right text-sm" style={{ color: customization.colors.paragraph }}>
                                                <p>{edu.start} - {edu.end}</p>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Dynamic Extra Sections */}
                    {Array.isArray(portfolio.extraSections) && portfolio.extraSections.length > 0 && (
                        <div className="p-6 border-t" style={{ borderColor: customization.colors.paragraph + '20' }}>
                            {portfolio.extraSections.map((section, sIdx) => (
                                (section?.items?.length > 0) ? (
                                    <div key={sIdx} className="mb-8">
                                        <h2 className="text-xl font-semibold mb-4" style={{ color: customization.colors.heading }}>{section.title || section.key}</h2>
                                        <div className="space-y-4">
                                            {section.items.map((item, iIdx) => (
                                                <div key={iIdx} className="border rounded-md p-4" style={{ borderColor: customization.colors.paragraph + '30' }}>
                                                    {/* Generic renderer: print common fields nicely */}
                                                    {item.title && <p className="font-medium" style={{ color: customization.colors.subheading }}>{item.title}</p>}
                                                    {item.name && <p className="font-medium" style={{ color: customization.colors.subheading }}>{item.name}</p>}
                                                    {item.venue && <p className="text-sm" style={{ color: customization.colors.paragraph }}>{item.venue} {item.year ? `• ${item.year}` : ''}</p>}
                                                    {item.client && <p className="text-sm" style={{ color: customization.colors.paragraph }}>Client: {item.client}</p>}
                                                    {item.description && <p className="mt-1" style={{ color: customization.colors.paragraph }}>{item.description}</p>}
                                                    {Array.isArray(item.tech) && item.tech.length > 0 && (
                                                        <div className="flex flex-wrap gap-2 mt-2">
                                                            {item.tech.map((t, tIdx) => (
                                                                <span key={tIdx} className="px-2 py-0.5 bg-gray-100 text-gray-700 rounded text-xs">{t}</span>
                                                            ))}
                                                        </div>
                                                    )}
                                                    {item.link && (
                                                        <a href={item.link} target="_blank" rel="noopener noreferrer" className="inline-block mt-2 text-blue-600 hover:text-blue-800 text-sm">View</a>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ) : null
                            ))}
                        </div>
                    )}
                </div>

                {/* Action Buttons */}
                {portfolioId && (
                    <div className="mt-8 flex justify-center gap-4">
                        <button
                            onClick={handleStartEdit}
                            className="px-8 py-4 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors flex items-center gap-3 text-lg font-semibold shadow-lg"
                        >
                            <FaEdit className="text-xl" />
                            Edit Portfolio
                        </button>
                        <button
                            onClick={handleSaveAndDashboard}
                            disabled={isUpdating}
                            className="px-8 py-4 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors flex items-center gap-3 text-lg font-semibold shadow-lg disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <FaDownload className="text-xl" />
                            {isUpdating ? 'Saving...' : 'Save & Dashboard'}
                        </button>
                        <button
                            onClick={handleDeploy}
                            disabled={isDeploying}
                            className="px-8 py-4 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors flex items-center gap-3 text-lg font-semibold shadow-lg disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <FaShare className="text-xl" />
                            {isDeploying ? 'Deploying...' : 'Deploy'}
                        </button>
                    </div>
                )}
            </div>

            {/* Portfolio Edit Modal */}
            <PortfolioEditModal
                isOpen={isEditing}
                onClose={() => setIsEditing(false)}
                portfolio={portfolio}
                onSave={handleSaveEditModal}
            />

            {/* Deploy Success Modal */}
            {showDeployModal && (
                <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-xl shadow-2xl max-w-2xl w-full p-8">
                        <div className="text-center">
                            <div className="mx-auto w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-6">
                                <FaShare className="text-4xl text-green-600" />
                            </div>
                            <h2 className="text-3xl font-bold text-gray-900 mb-3">Portfolio Deployed Successfully!</h2>
                            <p className="text-gray-600 mb-6">Your portfolio is now live and accessible from anywhere.</p>
                            
                            <div className="bg-gray-50 rounded-lg p-6 mb-6">
                                <label className="block text-sm font-medium text-gray-700 mb-3">Your Portable Link:</label>
                                <div className="flex items-center gap-3">
                                    <input
                                        type="text"
                                        value={deployedLink}
                                        readOnly
                                        className="flex-1 px-4 py-3 border-2 border-gray-300 rounded-lg bg-white text-gray-800 font-mono text-sm"
                                    />
                                    <button
                                        onClick={copyDeployLink}
                                        className="px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors flex items-center gap-2 font-semibold"
                                    >
                                        <FaCopy />
                                        Copy
                                    </button>
                                </div>
                            </div>

                            <div className="flex gap-4 justify-center">
                                <button
                                    onClick={() => window.open(deployedLink, '_blank')}
                                    className="px-6 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors flex items-center gap-2 font-semibold"
                                >
                                    <FaEye />
                                    View Live
                                </button>
                                <button
                                    onClick={() => setShowDeployModal(false)}
                                    className="px-6 py-3 bg-gray-200 text-gray-800 rounded-lg hover:bg-gray-300 transition-colors font-semibold"
                                >
                                    Close
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default PortfolioDisplay;

import React, { useState } from 'react';
import { FaTimes, FaSave, FaUser, FaBriefcase, FaGraduationCap, FaProjectDiagram, FaCertificate, FaTrophy } from 'react-icons/fa';

const PortfolioEditModal = ({ portfolio, onSave, onClose, isOpen }) => {
  if (!isOpen) return null;
  const [activeSection, setActiveSection] = useState('basic');
  const [editData, setEditData] = useState({
    title: portfolio?.title || 'Professional Portfolio',
    header: {
      name: portfolio?.header?.name || '',
      shortAbout: portfolio?.header?.shortAbout || '',
      location: portfolio?.header?.location || '',
      contacts: {
        email: portfolio?.header?.contacts?.email || '',
        phone: portfolio?.header?.contacts?.phone || '',
        website: portfolio?.header?.contacts?.website || '',
        linkedin: portfolio?.header?.contacts?.linkedin || '',
        github: portfolio?.header?.contacts?.github || '',
        twitter: portfolio?.header?.contacts?.twitter || '',
      },
      skills: Array.isArray(portfolio?.header?.skills) ? portfolio.header.skills : [],
    },
    summary: portfolio?.summary || '',
    workExperience: Array.isArray(portfolio?.workExperience) ? portfolio.workExperience : [],
    education: Array.isArray(portfolio?.education) ? portfolio.education : [],
    extraSections: Array.isArray(portfolio?.extraSections) ? portfolio.extraSections : [],
  });

  const [saving, setSaving] = useState(false);

  const sections = [
    { id: 'basic', name: 'Basic Info', icon: FaUser },
    { id: 'experience', name: 'Experience', icon: FaBriefcase },
    { id: 'education', name: 'Education', icon: FaGraduationCap },
    { id: 'projects', name: 'Projects', icon: FaProjectDiagram },
    { id: 'certificates', name: 'Certificates', icon: FaCertificate },
    { id: 'achievements', name: 'Achievements', icon: FaTrophy },
  ];

  const handleSave = async () => {
    setSaving(true);
    try {
      await onSave(editData);
    } finally {
      setSaving(false);
    }
  };

  const addWorkExperience = () => {
    setEditData({
      ...editData,
      workExperience: [...editData.workExperience, { 
        company: '', 
        title: '', 
        location: '', 
        contract: 'Full-time',
        start: '', 
        end: '', 
        description: '',
        link: ''
      }]
    });
  };

  const updateWorkExperience = (index, field, value) => {
    const updated = [...editData.workExperience];
    updated[index] = { ...updated[index], [field]: value };
    setEditData({ ...editData, workExperience: updated });
  };

  const removeWorkExperience = (index) => {
    setEditData({
      ...editData,
      workExperience: editData.workExperience.filter((_, i) => i !== index)
    });
  };

  const addEducation = () => {
    setEditData({
      ...editData,
      education: [...editData.education, { school: '', degree: '', start: '', end: '' }]
    });
  };

  const updateEducation = (index, field, value) => {
    const updated = [...editData.education];
    updated[index] = { ...updated[index], [field]: value };
    setEditData({ ...editData, education: updated });
  };

  const removeEducation = (index) => {
    setEditData({
      ...editData,
      education: editData.education.filter((_, i) => i !== index)
    });
  };

  const addExtraSection = (sectionType) => {
    const sectionTitles = {
      projects: 'Projects',
      certificates: 'Certificates',
      achievements: 'Achievements'
    };
    setEditData({
      ...editData,
      extraSections: [...editData.extraSections, { 
        key: `${sectionType}-${Date.now()}`, 
        title: sectionTitles[sectionType] || 'New Section', 
        items: [] 
      }]
    });
  };

  const updateExtraSectionTitle = (index, title) => {
    const updated = [...editData.extraSections];
    updated[index] = { ...updated[index], title };
    setEditData({ ...editData, extraSections: updated });
  };

  const addExtraItem = (sectionIndex) => {
    const updated = [...editData.extraSections];
    updated[sectionIndex].items.push({ 
      title: '', 
      name: '', 
      description: '', 
      link: '',
      venue: '',
      year: '',
      tech: []
    });
    setEditData({ ...editData, extraSections: updated });
  };

  const updateExtraItem = (sectionIndex, itemIndex, field, value) => {
    const updated = [...editData.extraSections];
    updated[sectionIndex].items[itemIndex] = { 
      ...updated[sectionIndex].items[itemIndex], 
      [field]: value 
    };
    setEditData({ ...editData, extraSections: updated });
  };

  const removeExtraItem = (sectionIndex, itemIndex) => {
    const updated = [...editData.extraSections];
    updated[sectionIndex].items = updated[sectionIndex].items.filter((_, i) => i !== itemIndex);
    setEditData({ ...editData, extraSections: updated });
  };

  const removeExtraSection = (index) => {
    setEditData({
      ...editData,
      extraSections: editData.extraSections.filter((_, i) => i !== index)
    });
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 z-50 overflow-y-auto">
      <div className="min-h-screen px-4 py-8">
        <div className="max-w-6xl mx-auto bg-white rounded-xl shadow-2xl">
          {/* Header */}
          <div className="border-b px-8 py-6 flex items-center justify-between bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-t-xl">
            <div>
              <h2 className="text-2xl font-bold flex items-center gap-3">
                <FaUser />
                Edit Portfolio
              </h2>
              <p className="text-blue-100 mt-1">Update your portfolio information</p>
            </div>
            <div className="flex gap-3">
              <button
                onClick={onClose}
                className="px-6 py-2 bg-white/20 hover:bg-white/30 rounded-lg transition-colors flex items-center gap-2"
              >
                <FaTimes />
                Cancel
              </button>
              <button
                onClick={handleSave}
                disabled={saving}
                className="px-6 py-2 bg-white text-blue-600 hover:bg-blue-50 rounded-lg transition-colors flex items-center gap-2 font-semibold"
              >
                <FaSave />
                {saving ? 'Saving...' : 'Save Changes'}
              </button>
            </div>
          </div>

          <div className="flex">
            {/* Sidebar */}
            <div className="w-64 border-r bg-gray-50 p-4">
              <h3 className="text-sm font-semibold text-gray-500 uppercase mb-3">Sections</h3>
              <div className="space-y-1">
                {sections.map((section) => {
                  const Icon = section.icon;
                  return (
                    <button
                      key={section.id}
                      onClick={() => setActiveSection(section.id)}
                      className={`w-full text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors ${
                        activeSection === section.id
                          ? 'bg-blue-100 text-blue-700 font-medium'
                          : 'text-gray-700 hover:bg-gray-100'
                      }`}
                    >
                      <Icon className="text-lg" />
                      {section.name}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Content */}
            <div className="flex-1 p-8 max-h-[70vh] overflow-y-auto">
              {/* Basic Information */}
              {activeSection === 'basic' && (
                <div>
                  <h3 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
                    <FaUser className="text-blue-600" />
                    Basic Information
                  </h3>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Portfolio Title</label>
                      <input
                        type="text"
                        value={editData.title}
                        onChange={(e) => setEditData({ ...editData, title: e.target.value })}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="Professional Portfolio"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Full Name</label>
                      <input
                        type="text"
                        value={editData.header.name}
                        onChange={(e) => setEditData({ ...editData, header: { ...editData.header, name: e.target.value } })}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="GIRI DHARAN B"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Professional Tagline</label>
                      <input
                        type="text"
                        value={editData.header.shortAbout}
                        onChange={(e) => setEditData({ ...editData, header: { ...editData.header, shortAbout: e.target.value } })}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="Aspiring AI Engineer with expertise in Generative AI, model finetuning, and application development"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Location</label>
                      <input
                        type="text"
                        value={editData.header.location}
                        onChange={(e) => setEditData({ ...editData, header: { ...editData.header, location: e.target.value } })}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="Tiruchengode, Namakkal, TN"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Professional Summary</label>
                      <textarea
                        value={editData.summary}
                        onChange={(e) => setEditData({ ...editData, summary: e.target.value })}
                        className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent min-h-[120px]"
                        placeholder="Write a brief summary about yourself..."
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-3">Contact Information</label>
                      <div className="grid grid-cols-2 gap-4">
                        <div>
                          <label className="block text-xs text-gray-600 mb-1">Email</label>
                          <input
                            type="email"
                            value={editData.header.contacts.email}
                            onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, email: e.target.value } } })}
                            className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                            placeholder="giri.2004k@gmail.com"
                          />
                        </div>
                        <div>
                          <label className="block text-xs text-gray-600 mb-1">Phone</label>
                          <input
                            type="text"
                            value={editData.header.contacts.phone}
                            onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, phone: e.target.value } } })}
                            className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                            placeholder="+91 6383608069"
                          />
                        </div>
                        <div>
                          <label className="block text-xs text-gray-600 mb-1">Website</label>
                          <input
                            type="url"
                            value={editData.header.contacts.website}
                            onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, website: e.target.value } } })}
                            className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                            placeholder="https://chatpulse.dev"
                          />
                        </div>
                        <div>
                          <label className="block text-xs text-gray-600 mb-1">LinkedIn</label>
                          <input
                            type="text"
                            value={editData.header.contacts.linkedin}
                            onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, linkedin: e.target.value } } })}
                            className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                            placeholder="giri-dharan-667163260"
                          />
                        </div>
                        <div>
                          <label className="block text-xs text-gray-600 mb-1">GitHub</label>
                          <input
                            type="text"
                            value={editData.header.contacts.github}
                            onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, github: e.target.value } } })}
                            className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                            placeholder="Giridharan002"
                          />
                        </div>
                        <div>
                          <label className="block text-xs text-gray-600 mb-1">Twitter</label>
                          <input
                            type="text"
                            value={editData.header.contacts.twitter}
                            onChange={(e) => setEditData({ ...editData, header: { ...editData.header, contacts: { ...editData.header.contacts, twitter: e.target.value } } })}
                            className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                            placeholder="@username"
                          />
                        </div>
                      </div>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Skills (comma separated)</label>
                      <input
